import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async analyzeProductImage(base64Image: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
            { text: "Identifique este produto de ferramentas para comunicação visual. Retorne apenas o nome provável do item." }
          ]
        }
      });
      return response.text || "Produto não identificado";
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return "Erro na identificação";
    }
  },

  async generateProductDescription(productName: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Escreva uma descrição técnica B2B persuasiva para o produto: ${productName}. Foco em durabilidade e eficiência para o lojista.`,
      });
      return response.text || "";
    } catch (error) {
      console.error("Gemini Text Error:", error);
      return "Descrição indisponível.";
    }
  }
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Camera, X, RefreshCw } from 'lucide-react';

interface ScannerProps {
  onScan: (code: string) => void;
  onClose: () => void;
}

const Scanner: React.FC<ScannerProps> = ({ onScan, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment' } 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        setError('Não foi possível acessar a câmera.');
      }
    }
    startCamera();

    return () => {
      if (videoRef.current?.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(track => track.stop());
      }
    };
  }, []);

  const captureFrame = useCallback(() => {
    if (!videoRef.current || !canvasRef.current) return;

    // In a real app, we'd use a barcode library here. 
    // We simulate a successful scan for the demo when the user clicks 'Scan'.
    onScan('EXF-12345'); 
  }, [onScan]);

  return (
    <div className="fixed inset-0 bg-black z-50 flex flex-col">
      <div className="flex justify-between items-center p-4 text-white">
        <h2 className="text-lg font-bold">Módulo Scan & Buy</h2>
        <button onClick={onClose}><X size={28} /></button>
      </div>

      <div className="flex-1 relative flex items-center justify-center overflow-hidden">
        {error ? (
          <div className="text-white text-center p-8">
            <p>{error}</p>
            <button 
              onClick={() => window.location.reload()}
              className="mt-4 bg-blue-600 px-4 py-2 rounded-lg"
            >
              Tentar Novamente
            </button>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="absolute inset-0 w-full h-full object-cover"
            />
            {/* Scanner Overlay UI */}
            <div className="relative z-10 w-64 h-64 border-2 border-blue-400 rounded-lg shadow-[0_0_0_100vmax_rgba(0,0,0,0.5)]">
              <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-blue-500 -mt-1 -ml-1"></div>
              <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-blue-500 -mt-1 -mr-1"></div>
              <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-blue-500 -mb-1 -ml-1"></div>
              <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-blue-500 -mb-1 -mr-1"></div>

              <div className="absolute top-1/2 left-0 w-full h-0.5 bg-blue-500/50 animate-pulse"></div>
            </div>
          </>
        )}
      </div>

      <div className="bg-black/80 p-8 flex flex-col items-center">
        <p className="text-white text-sm mb-6 opacity-80">Aponte para o QR Code ou Código de Barras na prateleira</p>
        <button 
          onClick={captureFrame}
          className="w-20 h-20 bg-white rounded-full flex items-center justify-center border-4 border-blue-600 shadow-xl active:scale-95 transition-transform"
        >
          <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center text-white">
            <Camera size={32} />
          </div>
        </button>
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default Scanner;

import React, { useState } from 'react';
import { Camera, ShoppingCart, Clock, Search, ChevronRight, Plus, Minus, CheckCircle2, History } from 'lucide-react';
import { MOCK_PRODUCTS, MOCK_USER_SHOPKEEPER } from '../constants';
import { Product, CartItem, Order } from '../types';
import Scanner from './Scanner';

const ShopkeeperApp: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [view, setView] = useState<'home' | 'cart' | 'history'>('home');
  const [scannedProduct, setScannedProduct] = useState<Product | null>(null);
  const [orders, setOrders] = useState<Order[]>([]);

  const addToCart = (product: Product, quantity: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      return [...prev, { ...product, quantity }];
    });
    setScannedProduct(null);
    setIsScanning(false);
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const finalizeOrder = () => {
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      date: new Date().toLocaleDateString('pt-BR'),
      items: [...cart],
      total,
      status: 'Pendente'
    };
    setOrders([newOrder, ...orders]);
    setCart([]);
    setView('history');
  };

  const handleScanSuccess = (code: string) => {
    // In real app, fetch from API. Here we mock:
    const found = MOCK_PRODUCTS.find(p => p.sku === code || p.barcode === code) || MOCK_PRODUCTS[0];
    setScannedProduct(found);
    setIsScanning(false);
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 flex flex-col relative pb-20">
      {/* App Header */}
      <header className="bg-blue-600 text-white p-6 rounded-b-3xl shadow-lg sticky top-0 z-40">
        <div className="flex justify-between items-start mb-4">
          <div>
            <h1 className="text-xl font-bold">Exfak Express</h1>
            <p className="text-xs opacity-80 uppercase tracking-widest">{MOCK_USER_SHOPKEEPER.name}</p>
          </div>
          <button onClick={onLogout} className="text-xs bg-white/20 px-3 py-1 rounded-full">Sair</button>
        </div>
        <div className="relative">
          <input 
            type="text" 
            placeholder="Buscar por SKU ou Nome..."
            className="w-full bg-white/10 border border-white/20 rounded-2xl py-3 px-10 text-white placeholder-white/60 focus:bg-white/20 outline-none transition-all"
          />
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-white/60" size={18} />
        </div>
      </header>

      {/* Main View Area */}
      <main className="p-6 flex-1">
        {view === 'home' && (
          <div className="space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 text-center flex flex-col items-center">
              <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center text-blue-600 mb-4">
                <Camera size={32} />
              </div>
              <h3 className="font-bold text-lg mb-1">Reposição Rápida</h3>
              <p className="text-sm text-gray-500 mb-6">Escaneie o código de barras na prateleira para adicionar ao carrinho instantaneamente.</p>
              <button 
                onClick={() => setIsScanning(true)}
                className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-blue-200 shadow-lg active:scale-95 transition-transform flex items-center justify-center gap-2"
              >
                <Camera size={20} />
                Abrir Scanner
              </button>
            </div>

            <section>
              <h2 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                <History size={18} className="text-blue-600" />
                Destaques de Reposição
              </h2>
              <div className="grid grid-cols-2 gap-4">
                {MOCK_PRODUCTS.slice(0, 2).map(p => (
                  <div key={p.id} className="bg-white p-3 rounded-2xl shadow-sm border border-gray-100">
                    <img src={p.imageUrl} className="w-full h-32 object-cover rounded-xl mb-3" />
                    <p className="text-sm font-bold truncate">{p.name}</p>
                    <p className="text-blue-600 font-black text-lg">R$ {p.price.toFixed(2)}</p>
                    <button className="mt-2 w-full text-xs font-bold text-blue-600 py-2 rounded-lg border border-blue-100 hover:bg-blue-50">Ver mais</button>
                  </div>
                ))}
              </div>
            </section>
          </div>
        )}

        {view === 'cart' && (
          <div className="space-y-4">
            <h2 className="text-2xl font-black text-gray-800 mb-6">Meu Carrinho</h2>
            {cart.length === 0 ? (
              <div className="text-center py-20">
                <ShoppingCart size={64} className="mx-auto text-gray-200 mb-4" />
                <p className="text-gray-500">Seu carrinho está vazio.</p>
              </div>
            ) : (
              <>
                <div className="space-y-3">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white p-4 rounded-2xl shadow-sm flex gap-4 items-center">
                      <img src={item.imageUrl} className="w-16 h-16 rounded-xl object-cover" />
                      <div className="flex-1">
                        <h4 className="font-bold text-sm">{item.name}</h4>
                        <p className="text-blue-600 font-bold">R$ {(item.price * item.quantity).toFixed(2)}</p>
                        <div className="flex items-center gap-4 mt-2">
                           <button onClick={() => updateQuantity(item.id, -1)} className="p-1 rounded bg-gray-100"><Minus size={14}/></button>
                           <span className="font-bold text-sm">{item.quantity}</span>
                           <button onClick={() => updateQuantity(item.id, 1)} className="p-1 rounded bg-gray-100"><Plus size={14}/></button>
                        </div>
                      </div>
                      <button onClick={() => removeFromCart(item.id)} className="text-red-400">
                        <Minus size={18} />
                      </button>
                    </div>
                  ))}
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-md mt-8 space-y-3">
                  <div className="flex justify-between text-sm text-gray-500">
                    <span>Subtotal</span>
                    <span>R$ {cart.reduce((s, i) => s + (i.price * i.quantity), 0).toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm text-gray-500">
                    <span>Impostos (IPI/ST estimado)</span>
                    <span>R$ {(cart.reduce((s, i) => s + (i.price * i.quantity), 0) * 0.12).toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between font-black text-xl pt-3 border-t">
                    <span>Total</span>
                    <span className="text-blue-600">R$ {(cart.reduce((s, i) => s + (i.price * i.quantity), 0) * 1.12).toFixed(2)}</span>
                  </div>
                  <button 
                    onClick={finalizeOrder}
                    className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold mt-4 shadow-lg"
                  >
                    Finalizar Pedido
                  </button>
                </div>
              </>
            )}
          </div>
        )}

        {view === 'history' && (
          <div className="space-y-4">
             <h2 className="text-2xl font-black text-gray-800 mb-6">Pedidos</h2>
             {orders.length === 0 ? (
               <div className="text-center py-20 text-gray-400">Nenhum pedido realizado recentemente.</div>
             ) : (
               orders.map(order => (
                 <div key={order.id} className="bg-white p-5 rounded-2xl shadow-sm border-l-4 border-blue-500">
                    <div className="flex justify-between items-start mb-3">
                      <div>
                        <p className="text-xs text-gray-400 font-bold uppercase">ID: {order.id}</p>
                        <p className="text-sm font-bold">{order.date}</p>
                      </div>
                      <span className="px-3 py-1 bg-blue-50 text-blue-600 text-[10px] font-black rounded-full uppercase tracking-tighter">
                        {order.status}
                      </span>
                    </div>
                    <p className="text-sm text-gray-600 mb-4">{order.items.length} itens no pedido</p>
                    <div className="flex justify-between items-center pt-3 border-t">
                      <span className="font-bold">Total do Pedido</span>
                      <span className="font-black text-blue-600">R$ {order.total.toFixed(2)}</span>
                    </div>
                 </div>
               ))
             )}
          </div>
        )}
      </main>

      {/* Bottom Tabs */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-100 flex justify-around p-3 z-50">
        <button 
          onClick={() => setView('home')}
          className={`flex flex-col items-center gap-1 transition-colors ${view === 'home' ? 'text-blue-600' : 'text-gray-400'}`}
        >
          <Search size={24} />
          <span className="text-[10px] font-bold">Catálogo</span>
        </button>
        <button 
          onClick={() => setIsScanning(true)}
          className="flex flex-col items-center gap-1 -mt-8"
        >
          <div className="w-14 h-14 bg-blue-600 rounded-full flex items-center justify-center text-white shadow-lg border-4 border-white">
            <Camera size={24} />
          </div>
          <span className="text-[10px] font-bold text-blue-600">Scan</span>
        </button>
        <button 
          onClick={() => setView('cart')}
          className={`flex flex-col items-center gap-1 transition-colors ${view === 'cart' ? 'text-blue-600' : 'text-gray-400'}`}
        >
          <div className="relative">
            <ShoppingCart size={24} />
            {cart.length > 0 && <span className="absolute -top-2 -right-2 bg-red-500 text-white text-[10px] w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">{cart.length}</span>}
          </div>
          <span className="text-[10px] font-bold">Carrinho</span>
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 transition-colors ${view === 'history' ? 'text-blue-600' : 'text-gray-400'}`}
        >
          <Clock size={24} />
          <span className="text-[10px] font-bold">Pedidos</span>
        </button>
      </nav>

      {/* Product Detail Modal (from Scan) */}
      {scannedProduct && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex items-end">
          <div className="bg-white w-full max-w-md mx-auto rounded-t-[32px] p-8 animate-slide-up">
            <div className="flex justify-center mb-6">
              <div className="w-12 h-1.5 bg-gray-200 rounded-full"></div>
            </div>
            <div className="flex gap-6 mb-6">
              <img src={scannedProduct.imageUrl} className="w-24 h-24 rounded-2xl object-cover shadow-sm" />
              <div className="flex-1">
                <p className="text-xs font-bold text-blue-500 mb-1">{scannedProduct.sku}</p>
                <h3 className="text-xl font-bold leading-tight mb-2">{scannedProduct.name}</h3>
                <div className="flex items-center gap-2">
                  <span className="px-2 py-0.5 bg-green-50 text-green-600 text-[10px] font-bold rounded">Em Estoque</span>
                  <span className="text-xs text-gray-400">{scannedProduct.stock} un disponíveis</span>
                </div>
              </div>
            </div>
            <p className="text-gray-500 text-sm mb-6 leading-relaxed">
              {scannedProduct.description}
            </p>
            <div className="flex items-center justify-between mb-8">
              <div>
                <p className="text-xs text-gray-400 uppercase font-bold">Preço Unitário</p>
                <p className="text-2xl font-black text-blue-600">R$ {scannedProduct.price.toFixed(2)}</p>
              </div>
              <div className="flex items-center bg-gray-100 rounded-2xl p-2 gap-4">
                <button className="w-10 h-10 bg-white rounded-xl shadow-sm flex items-center justify-center text-blue-600"><Minus size={18}/></button>
                <span className="font-black text-lg px-2">1</span>
                <button className="w-10 h-10 bg-white rounded-xl shadow-sm flex items-center justify-center text-blue-600"><Plus size={18}/></button>
              </div>
            </div>
            <div className="flex gap-4">
              <button 
                onClick={() => setScannedProduct(null)}
                className="flex-1 py-4 text-gray-400 font-bold"
              >
                Cancelar
              </button>
              <button 
                onClick={() => addToCart(scannedProduct, 1)}
                className="flex-[2] bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-100"
              >
                Adicionar ao Carrinho
              </button>
            </div>
          </div>
        </div>
      )}

      {isScanning && <Scanner onScan={handleScanSuccess} onClose={() => setIsScanning(false)} />}
    </div>
  );
};

export default ShopkeeperApp;

