            <div className="bg-slate-50 p-6 rounded-3xl mb-8">
              <p className="text-xs text-slate-400 uppercase font-black tracking-widest mb-2">Descrição Técnica</p>
              <p className="text-slate-600 text-sm leading-relaxed italic">
                "{selectedProduct.description}"
              </p>
            </div>

            <div className="flex items-center justify-between mb-10">
              <div>
                <p className="text-[10px] text-slate-400 uppercase font-black tracking-widest mb-1">Preço B2B</p>
                <p className="text-3xl font-black text-slate-900">R$ {selectedProduct.price.toFixed(2)}</p>
              </div>
              <div className="flex items-center bg-slate-100 rounded-2xl p-2 gap-5 shadow-inner">
                <button 
                  onClick={() => setOrderQuantity(q => Math.max(1, q - 1))}
                  className="w-12 h-12 bg-white rounded-xl shadow-sm flex items-center justify-center text-slate-400 active:bg-slate-50 transition-colors"
                >
                  <Minus size={20}/>
                </button>
                <span className="font-black text-xl px-2 min-w-[20px] text-center">{orderQuantity}</span>
                <button 
                  onClick={() => setOrderQuantity(q => q + 1)}
                  className="w-12 h-12 bg-white rounded-xl shadow-sm flex items-center justify-center text-blue-600 active:bg-slate-50 transition-colors"
                >
                  <Plus size={20}/>
                </button>
