            </div>

            <div className="flex gap-4">
              <button 
                onClick={() => setSelectedProduct(null)}
                className="flex-1 py-5 text-slate-400 font-black text-sm uppercase tracking-widest hover:text-slate-600 transition-colors"
              >
                Voltar
              </button>
              <button 
                onClick={() => addToCart(selectedProduct, orderQuantity)}
                className="flex-[2] bg-blue-600 text-white py-5 rounded-2xl font-black text-sm uppercase tracking-widest shadow-2xl shadow-blue-200 active:scale-95 transition-all"
