import React, { useState } from 'react';
import { UserRole, Product } from './types';
import ShopkeeperApp from './components/ShopkeeperApp';
import AdminDashboard from './components/AdminDashboard';
import { MOCK_PRODUCTS } from './constants';
import { LogIn, ShieldCheck, Box } from 'lucide-react';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [role, setRole] = useState<UserRole | null>(null);
  const [credentials, setCredentials] = useState({ cnpj: '', password: '' });

  // Lifting state: products are now managed at the top level
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);

  const handleLogin = (e: React.FormEvent, selectedRole: UserRole) => {
    e.preventDefault();
    setRole(selectedRole);
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setRole(null);
    setCredentials({ cnpj: '', password: '' });
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-slate-900 to-black">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl overflow-hidden p-8 md:p-12 border border-amber-500/20">
          <div className="text-center mb-10">
            <div className="inline-block p-4 bg-gradient-to-tr from-amber-200 via-yellow-500 to-amber-700 rounded-2xl text-white mb-4 shadow-lg shadow-amber-500/20">
              <Box size={40} className="stroke-[2.5]" />
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tighter uppercase">
              Exfak <span className="bg-gradient-to-r from-amber-600 to-yellow-500 bg-clip-text text-transparent">Express</span>
            </h1>
            <p className="text-slate-400 font-medium">Portal de Reposição Inteligente</p>
          </div>

          <form className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">CNPJ / Usuário</label>
              <input 
                type="text" 
                value={credentials.cnpj}
                onChange={(e) => setCredentials({...credentials, cnpj: e.target.value})}
                placeholder="00.000.000/0001-00" 
                className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-amber-100 outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Senha de Acesso</label>
              <input 
                type="password" 
                value={credentials.password}
                onChange={(e) => setCredentials({...credentials, password: e.target.value})}
                placeholder="••••••••" 
                className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-amber-100 outline-none transition-all"
              />
            </div>

            <div className="flex flex-col gap-3 pt-4">
              <button 
                onClick={(e) => handleLogin(e, UserRole.SHOPKEEPER)}
                className="w-full bg-gradient-to-r from-amber-600 to-yellow-500 hover:from-amber-700 hover:to-yellow-600 text-white font-bold py-4 rounded-2xl transition-all shadow-xl shadow-amber-200 flex items-center justify-center gap-2"
              >
                <LogIn size={20} />
                Entrar como Lojista
              </button>
              <button 
                onClick={(e) => handleLogin(e, UserRole.ADMIN)}
                className="w-full bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold py-4 rounded-2xl transition-all flex items-center justify-center gap-2"
              >
                <ShieldCheck size={20} />
                Acesso Administrativo
              </button>
            </div>
          </form>

          <p className="mt-8 text-center text-xs text-slate-400">
            Precisa de ajuda? <a href="#" className="text-amber-600 font-bold hover:underline">Falar com Suporte</a>
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen">
      {role === UserRole.ADMIN ? (
        <AdminDashboard 
          products={products} 
          setProducts={setProducts} 
          onLogout={handleLogout} 
        />
      ) : (
        <ShopkeeperApp 
          products={products}
          onLogout={handleLogout} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Package, Users, QrCode, Plus, Search, LogOut, Download, Mail, Edit2, Trash2, X, Image as ImageIcon, Menu } from 'lucide-react';
import { Product } from '../types';

interface AdminDashboardProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ products, setProducts, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'products' | 'clients' | 'orders'>('products');
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [showQrModal, setShowQrModal] = useState<Product | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const formRef = useRef<HTMLFormElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleEdit = (product: Product) => {
    setEditingProduct(product);
    setImagePreview(product.imageUrl);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Excluir este item permanentemente?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formRef.current) return;

    const formData = new FormData(formRef.current);
    const productData: Partial<Product> = {
      name: formData.get('name') as string,
      sku: formData.get('sku') as string,
      ncm: formData.get('ncm') as string,
      price: parseFloat(formData.get('price') as string) || 0,
      stock: parseInt(formData.get('stock') as string) || 0,
      description: formData.get('description') as string,
      imageUrl: imagePreview || `https://picsum.photos/seed/${Math.random()}/400/400`,
      barcode: editingProduct?.barcode || formData.get('sku') as string
    };

    if (editingProduct) {
      setProducts(prev => prev.map(p => 
        p.id === editingProduct.id ? { ...p, ...productData } as Product : p
      ));
    } else {
      const newProduct: Product = {
        ...productData,
        id: Math.random().toString(36).substr(2, 9),
      } as Product;
      setProducts(prev => [newProduct, ...prev]);
    }

    setShowModal(false);
    setEditingProduct(null);
    setImagePreview(null);
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar */}
      <aside className={`bg-slate-900 text-white flex flex-col transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'}`}>
        <div className="p-6 overflow-hidden flex items-center justify-between">
          {isSidebarOpen && <h1 className="text-xl font-black tracking-tighter text-amber-500 whitespace-nowrap">EXFAK <span className="text-white font-light">ADMIN</span></h1>}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-800 rounded-lg text-amber-500">
            <Menu size={24} />
          </button>
        </div>

        <nav className="flex-1 mt-6">
          <button 
            onClick={() => setActiveTab('products')}
            className={`w-full flex items-center gap-4 px-6 py-4 transition-colors ${activeTab === 'products' ? 'bg-amber-600' : 'hover:bg-slate-800'}`}
          >
            <Package size={20} className={activeTab === 'products' ? 'text-white' : 'text-amber-500'} />
            {isSidebarOpen && <span className="font-medium">Produtos</span>}
          </button>
          <button 
            onClick={() => setActiveTab('clients')}
            className={`w-full flex items-center gap-4 px-6 py-4 transition-colors ${activeTab === 'clients' ? 'bg-amber-600' : 'hover:bg-slate-800'}`}
          >
            <Users size={20} className={activeTab === 'clients' ? 'text-white' : 'text-amber-500'} />
            {isSidebarOpen && <span className="font-medium">Lojistas</span>}
          </button>
        </nav>

        <button 
          onClick={onLogout}
          className="p-6 flex items-center gap-4 text-slate-400 hover:text-white transition-colors border-t border-slate-800"
        >
          <LogOut size={20} />
          {isSidebarOpen && <span className="font-medium">Sair</span>}
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex justify-between items-center mb-8">
          <div>
            <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3">
              {activeTab === 'products' ? 'Gestão de Catálogo' : 'Rede de Lojistas'}
            </h2>
            <p className="text-slate-500">Controle total do inventário e parceiros</p>
          </div>

          <div className="flex gap-4">
            <button 
              onClick={() => { setEditingProduct(null); setImagePreview(null); setShowModal(true); }}
              className="bg-gradient-to-r from-amber-600 to-yellow-500 text-white px-6 py-2.5 rounded-xl flex items-center gap-2 hover:from-amber-700 transition-all shadow-lg shadow-amber-200 font-bold"
            >
              <Plus size={18} />
              Novo SKU
            </button>
          </div>
        </header>

        {activeTab === 'products' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr>
                  <th className="px-6 py-4 font-bold text-slate-600 uppercase text-[10px] tracking-widest">Produto</th>
                  <th className="px-6 py-4 font-bold text-slate-600 uppercase text-[10px] tracking-widest">SKU</th>
                  <th className="px-6 py-4 font-bold text-slate-600 uppercase text-[10px] tracking-widest">Estoque</th>
                  <th className="px-6 py-4 font-bold text-slate-600 uppercase text-[10px] tracking-widest">Preço Base</th>
                  <th className="px-6 py-4 font-bold text-slate-600 uppercase text-[10px] tracking-widest text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {products.length === 0 ? (
                  <tr><td colSpan={5} className="p-12 text-center text-slate-400">Nenhum produto cadastrado.</td></tr>
                ) : products.map((p) => (
                  <tr key={p.id} className="hover:bg-amber-50/30 transition-colors group">
                    <td className="px-6 py-4 flex items-center gap-4">
                      <img src={p.imageUrl} alt={p.name} className="w-12 h-12 rounded-xl object-cover bg-slate-100 shadow-sm" />
                      <div>
                        <p className="font-bold text-slate-800">{p.name}</p>
                        <p className="text-xs text-slate-400">NCM: {p.ncm}</p>
                      </div>
                    </td>
                    <td className="px-6 py-4">
