import React, { useState } from 'react';
import { Camera, Search, History, X, Info, ChevronRight, Box, Youtube } from 'lucide-react';
import { Product } from '../types';
import Scanner from './Scanner';

interface CatalogAppProps {
  products: Product[];
  onLogout: () => void;
}

const CatalogApp: React.FC<CatalogAppProps> = ({ products, onLogout }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.sku.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleScanSuccess = (code: string) => {
    const found = products.find(p => p.sku === code || p.barcode === code);
    if (found) {
      setSelectedProduct(found);
    }
    setIsScanning(false);
  };

  const getYouTubeEmbedUrl = (url?: string) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|\&v=)([^#\&\?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? `https://www.youtube.com/embed/${match[2]}` : null;
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-black flex flex-col relative pb-24 overflow-x-hidden border-x border-white/5">
      <header className="bg-black/80 backdrop-blur-xl text-white p-7 sticky top-0 z-40 border-b border-white/10">
        <div className="flex justify-between items-center mb-6">
          <div className="flex flex-col">
             <h1 className="text-2xl font-black italic tracking-tighter leading-none">EXFAK</h1>
             <span className="text-[8px] font-light tracking-[0.3em] uppercase opacity-50">Innovating Beyond</span>
          </div>
          <button 
            onClick={onLogout} 
            className="text-[9px] font-black border border-white/20 px-3 py-1.5 rounded-full uppercase tracking-widest hover:bg-white hover:text-black transition-colors"
          >
            Sair
          </button>
        </div>
        <div className="relative group">
          <input 
            type="text" 
            placeholder="Buscar soluções tecnológicas..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 px-12 text-sm text-white placeholder-white/20 focus:bg-white/10 focus:border-white/30 outline-none transition-all"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30 group-focus-within:text-white" size={18} />
        </div>
      </header>

      <main className="p-6 flex-1 space-y-10">
        <div className="bg-gradient-to-br from-zinc-900 to-black p-8 rounded-[2.5rem] border border-white/5 text-center flex flex-col items-center shadow-2xl">
          <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center text-black mb-6 shadow-[0_0_40px_rgba(255,255,255,0.1)]">
            <Camera size={36} className="stroke-[1.5]" />
          </div>
          <h3 className="font-black text-xl mb-2 text-white uppercase tracking-tighter italic">Consulta Inteligente</h3>
          <p className="text-xs text-white/40 mb-8 max-w-[220px] leading-relaxed">Escaneie o QR Code em nossos produtos para acessar especificações técnicas instantaneamente.</p>
          <button 
            onClick={() => setIsScanning(true)}
            className="w-full bg-white text-black py-5 rounded-2xl font-black text-xs shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3 uppercase tracking-[0.2em]"
          >
            Iniciar Scanner
          </button>
        </div>

        <section>
          <div className="flex justify-between items-center mb-6 px-2">
            <h2 className="font-black text-white flex items-center gap-2 uppercase tracking-widest text-[10px] opacity-40">
              Catálogo de Produtos
            </h2>
          </div>

          {filteredProducts.length === 0 ? (
            <div className="text-center py-12 text-white/20 text-xs font-bold uppercase tracking-widest">
              Nenhum resultado encontrado
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-4">
              {filteredProducts.map(p => (
                <div 
                  key={p.id} 
                  onClick={() => setSelectedProduct(p)}
                  className="bg-zinc-900/40 p-5 rounded-[2rem] border border-white/5 flex gap-5 items-center hover:bg-zinc-900 transition-all cursor-pointer group"
                >
                  <img src={p.imageUrl} className="w-20 h-20 aspect-square object-cover rounded-2xl bg-black border border-white/5" alt={p.name} />
                  <div className="flex-1">
                    <p className="text-[9px] font-black text-white/30 mb-1 uppercase tracking-[0.2em]">{p.sku}</p>
                    <p className="text-md font-black text-white uppercase italic leading-tight group-hover:translate-x-1 transition-transform">{p.name}</p>
                    <div className="mt-2 flex items-center gap-1.5">
                       <span className="w-1.5 h-1.5 bg-white rounded-full opacity-30"></span>
                       <span className="text-[10px] font-bold text-white/40 uppercase tracking-widest">Ver especificações</span>
                    </div>
                  </div>
                  <ChevronRight size={20} className="text-white/20 group-hover:text-white transition-colors" />
                </div>
              ))}
            </div>
          )}
        </section>
      </main>

      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-black/90 backdrop-blur-2xl border-t border-white/10 flex justify-center p-6 z-50 rounded-t-[2.5rem]">
        <button 
          onClick={() => setIsScanning(true)}
          className="flex flex-col items-center gap-1"
        >
          <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-black shadow-2xl active:scale-90 transition-transform">
            <Camera size={28} />
          </div>
          <span className="text-[9px] font-black uppercase tracking-widest text-white mt-2">Consultar</span>
        </button>
      </nav>

      {selectedProduct && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md z-[100] flex items-end">
          <div className="bg-zinc-950 w-full max-w-md mx-auto rounded-t-[3.5rem] p-10 animate-slide-up shadow-2xl border-t border-white/10 overflow-y-auto max-h-[95vh]">
            <div className="flex justify-center mb-8">
              <div className="w-16 h-1 bg-white/10 rounded-full"></div>
            </div>

            <div className="flex gap-6 mb-10 items-start">
              <div className="relative">
                <img src={selectedProduct.imageUrl} className="w-32 h-32 rounded-3xl object-cover shadow-2xl bg-black border border-white/10" />
                <div className="absolute -bottom-2 -right-2 bg-white text-black p-2 rounded-xl shadow-lg">
                   <Box size={16} />
                </div>
              </div>
              <div className="flex-1 pt-2">
                <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em] mb-2">{selectedProduct.sku}</p>
                <h3 className="text-2xl font-black text-white italic leading-none uppercase mb-4">{selectedProduct.name}</h3>
                <div className="inline-flex items-center px-3 py-1 bg-white/5 border border-white/10 rounded-full">
                  <span className="text-[8px] font-black text-white/60 uppercase tracking-widest">Solução Profissional</span>
                </div>
              </div>
            </div>

            <div className="space-y-6">
              {/* YouTube Video Section */}
              {getYouTubeEmbedUrl(selectedProduct.youtubeUrl) && (
                <div className="rounded-[2rem] overflow-hidden border border-white/10 aspect-video shadow-2xl bg-black">
                  <iframe 
                    width="100%" 
                    height="100%" 
                    src={getYouTubeEmbedUrl(selectedProduct.youtubeUrl) || ''} 
                    title="Product Demonstration" 
                    frameBorder="0" 
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                    allowFullScreen
                  ></iframe>
                </div>
              )}

              <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5">
                <div className="flex items-center gap-2 mb-4 text-white/30 uppercase font-black text-[9px] tracking-widest">
                  <Info size={14} />
                  <span>Descrição Técnica</span>
                </div>
                <p className="text-white/60 text-sm leading-relaxed font-light">
                  {selectedProduct.description}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 p-4 rounded-2xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">NCM Fiscal</p>
                  <p className="text-white text-xs font-mono">{selectedProduct.ncm}</p>
                </div>
                <div className="bg-white/5 p-4 rounded-2xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">Referência SKU</p>
                  <p className="text-white text-xs font-mono">{selectedProduct.sku}</p>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setSelectedProduct(null)}
              className="w-full mt-10 py-5 border border-white/10 text-white font-black text-xs uppercase tracking-[0.3em] rounded-2xl hover:bg-white hover:text-black transition-all"
            >
              Voltar ao Catálogo
            </button>
          </div>
        </div>
      )}

      {isScanning && <Scanner onScan={handleScanSuccess} onClose={() => setIsScanning(false)} />}
    </div>
  );
};

export default CatalogApp;

