import React, { useState } from 'react';
import { UserRole, Product } from './types';
import CatalogApp from './components/CatalogApp';
import AdminDashboard from './components/AdminDashboard';
import { MOCK_PRODUCTS } from './constants';
import { ShieldCheck, ArrowRight } from 'lucide-react';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [products, setProducts] = useState<Product[]>(MOCK_PRODUCTS);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsAdminMode(true);
    setIsLoggedIn(true);
  };

  const enterCatalog = () => {
    setIsAdminMode(false);
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdminMode(false);
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center p-6 font-sans relative overflow-hidden">
        <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-zinc-800/20 blur-[120px] rounded-full"></div>
        <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-zinc-800/20 blur-[120px] rounded-full"></div>

        <div className="w-full max-w-lg text-center z-10 space-y-12">
          <div className="flex flex-col items-center">
            <div className="mb-4">
               <h1 className="text-7xl font-black italic tracking-tighter text-white">5MAXX</h1>
               <p className="text-white text-sm font-light tracking-[0.4em] uppercase mt-[-0.5rem] bg-gradient-to-r from-amber-200 via-yellow-500 to-amber-700 bg-clip-text text-transparent">Innovating Beyond</p>
            </div>
            <div className="h-0.5 w-24 bg-gradient-to-r from-transparent via-amber-500 to-transparent opacity-50 mt-6"></div>
          </div>

          <div className="space-y-6">
            <h2 className="text-white/60 text-lg font-medium tracking-wide">Plataforma Institucional de Soluções</h2>

            <button 
              onClick={enterCatalog}
              className="group w-full bg-white text-black font-black py-6 rounded-2xl transition-all hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-3 text-lg uppercase tracking-widest shadow-[0_0_30px_rgba(255,255,255,0.1)]"
            >
              Explorar Catálogo
              <ArrowRight size={24} className="group-hover:translate-x-1 transition-transform" />
            </button>

            <button 
              onClick={handleAdminLogin}
              className="w-full bg-white/5 border border-white/10 text-white/40 hover:text-white hover:bg-white/10 font-bold py-4 rounded-2xl transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest"
            >
              <ShieldCheck size={18} />
              Acesso Restrito
            </button>
          </div>
        </div>

        <p className="absolute bottom-8 text-white/20 text-[10px] uppercase tracking-[0.4em] font-bold">
          © 2024 5MAXX do Brasil - All Rights Reserved
        </p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-zinc-950 text-white">
      {isAdminMode ? (
        <AdminDashboard 
          products={products} 
          setProducts={setProducts} 
          onLogout={handleLogout} 
        />
      ) : (
        <CatalogApp 
          products={products}
          onLogout={handleLogout} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Camera, Search, X, Info, ChevronRight, Box, Menu, LayoutGrid, Layers, Scissors, Tag } from 'lucide-react';
import { Product } from '../types';
import Scanner from './Scanner';

interface CatalogAppProps {
  products: Product[];
  onLogout: () => void;
}

const CatalogApp: React.FC<CatalogAppProps> = ({ products, onLogout }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  const categories = ['Espatulas', 'Estiletes', 'Feltros'];

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         p.sku.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory ? p.category === selectedCategory : true;
    return matchesSearch && matchesCategory;
  });

  const handleScanSuccess = (code: string) => {
    const found = products.find(p => p.sku === code || p.barcode === code);
    if (found) {
      setSelectedProduct(found);
    }
    setIsScanning(false);
  };

  const getYouTubeEmbedUrl = (url?: string) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|\&v=)([^#\&\?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? `https://www.youtube.com/embed/${match[2]}` : null;
  };

  const getCategoryIcon = (cat: string) => {
    switch (cat) {
      case 'Espatulas': return <LayoutGrid size={20} />;
      case 'Estiletes': return <Scissors size={20} />;
      case 'Feltros': return <Layers size={20} />;
      default: return <Tag size={20} />;
    }
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-black flex flex-col relative pb-24 overflow-x-hidden border-x border-white/5">
      {/* Category Sidebar/Menu Overlay */}
      {isMenuOpen && (
        <div className="fixed inset-0 z-[100] flex">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)}></div>
          <div className="relative w-72 bg-zinc-950 border-r border-white/10 h-full p-8 animate-slide-right flex flex-col">
             <div className="flex justify-between items-center mb-12">
               <h1 className="text-3xl font-black italic text-white">5MAXX</h1>
               <button onClick={() => setIsMenuOpen(false)} className="text-white/40"><X size={24} /></button>
             </div>

             <div className="space-y-4">
               <p className="text-[10px] font-black text-white/20 uppercase tracking-[0.3em] mb-4">Departamentos</p>
               <button 
                 onClick={() => { setSelectedCategory(null); setIsMenuOpen(false); }}
                 className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all ${!selectedCategory ? 'bg-white text-black font-black' : 'text-white/60 hover:bg-white/5'}`}
               >
                 <Box size={20} />
                 <span className="text-xs uppercase tracking-widest">Todos Produtos</span>
               </button>

               {categories.map(cat => (
                 <button 
                   key={cat}
                   onClick={() => { setSelectedCategory(cat); setIsMenuOpen(false); }}
                   className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all ${selectedCategory === cat ? 'bg-white text-black font-black' : 'text-white/60 hover:bg-white/5'}`}
                 >
                   {getCategoryIcon(cat)}
                   <span className="text-xs uppercase tracking-widest">{cat}</span>
                 </button>
               ))}
             </div>

             <div className="mt-auto pt-8 border-t border-white/10">
                <button onClick={onLogout} className="text-[10px] font-black uppercase tracking-widest text-white/40 hover:text-white flex items-center gap-2">
                  <X size={14} /> Encerrar Sessão
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-black text-white p-7 sticky top-0 z-40 border-b border-white/10">
        <div className="flex justify-between items-center mb-8">
          <button onClick={() => setIsMenuOpen(true)} className="p-2 -ml-2 text-white">
            <Menu size={28} />
          </button>
          <div className="flex flex-col items-center">
             <h1 className="text-3xl font-black italic tracking-tighter leading-none">5MAXX</h1>
             <span className="text-[7px] font-light tracking-[0.4em] uppercase opacity-40">Innovating Beyond</span>
          </div>
          <button onClick={() => setIsScanning(true)} className="p-2 -mr-2 text-white">
            <Camera size={26} />
          </button>
        </div>

        {/* Improved Contrast Search Bar */}
        <div className="relative group">
          <input 
            type="text" 
            placeholder="O que você procura hoje?"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-white border border-zinc-200 rounded-2xl py-4 px-12 text-sm text-black placeholder-zinc-400 focus:ring-4 focus:ring-amber-500/20 outline-none transition-all shadow-xl"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400" size={18} />
        </div>

        {selectedCategory && (
          <div className="mt-4 flex items-center gap-2">
            <span className="text-[10px] font-black uppercase tracking-widest text-white/40">Filtrando:</span>
            <button 
              onClick={() => setSelectedCategory(null)}
              className="bg-white/10 px-3 py-1 rounded-full text-[9px] font-black uppercase flex items-center gap-2 border border-white/10"
            >
              {selectedCategory} <X size={12} />
            </button>
          </div>
        )}
      </header>

      {/* Main Catalog View */}
      <main className="p-6 flex-1">
        <section>
          <div className="flex justify-between items-center mb-6 px-2">
            <h2 className="font-black text-white flex items-center gap-2 uppercase tracking-widest text-[10px] opacity-40">
              {selectedCategory || 'Coleção Completa'}
            </h2>
          </div>

          {filteredProducts.length === 0 ? (
            <div className="text-center py-24 text-white/20">
               <Box className="mx-auto mb-4 opacity-10" size={64} />
               <p className="text-xs font-black uppercase tracking-widest">Nenhum item disponível</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-5">
              {filteredProducts.map(p => (
                <div 
                  key={p.id} 
                  onClick={() => setSelectedProduct(p)}
                  className="bg-zinc-900/40 p-5 rounded-[2.5rem] border border-white/5 flex gap-5 items-center hover:bg-zinc-900 transition-all cursor-pointer group shadow-lg"
                >
                  <div className="relative">
                    <img src={p.imageUrl} className="w-24 h-24 aspect-square object-cover rounded-[1.5rem] bg-black border border-white/5 group-hover:scale-105 transition-transform" alt={p.name} />
                  </div>
                  <div className="flex-1">
                    <p className="text-[8px] font-black text-white/30 mb-1 uppercase tracking-[0.2em]">{p.sku}</p>
                    <p className="text-lg font-black text-white uppercase italic leading-tight group-hover:text-amber-500 transition-colors">{p.name}</p>
                    <div className="mt-3 inline-flex items-center gap-2 px-3 py-1 bg-white/5 border border-white/10 rounded-full">
                       <span className="text-[9px] font-black text-white/50 uppercase tracking-widest">Detalhes</span>
                       <ChevronRight size={14} className="text-white/30 group-hover:translate-x-1 transition-transform" />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>

      {/* Specification Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-md z-[110] flex items-end">
          <div className="bg-zinc-950 w-full max-w-md mx-auto rounded-t-[3.5rem] p-10 animate-slide-up shadow-2xl border-t border-white/10 overflow-y-auto max-h-[95vh]">
            <div className="flex justify-center mb-8">
              <div className="w-16 h-1 bg-white/10 rounded-full"></div>
            </div>

            <div className="flex gap-6 mb-10 items-start">
              <img src={selectedProduct.imageUrl} className="w-32 h-32 rounded-3xl object-cover shadow-2xl bg-black border border-white/10" />
              <div className="flex-1 pt-2">
                <p className="text-[9px] font-black text-white/40 uppercase tracking-[0.3em] mb-2">{selectedProduct.sku}</p>
                <h3 className="text-2xl font-black text-white italic leading-none uppercase mb-4">{selectedProduct.name}</h3>
                <div className="inline-flex items-center px-3 py-1 bg-white text-black rounded-full">
                  <span className="text-[8px] font-black uppercase tracking-widest">{selectedProduct.category}</span>
                </div>
              </div>
            </div>

            <div className="space-y-6">
              {getYouTubeEmbedUrl(selectedProduct.youtubeUrl) && (
                <div className="rounded-[2rem] overflow-hidden border border-white/10 aspect-video shadow-2xl bg-black">
                  <iframe 
                    width="100%" 
                    height="100%" 
                    src={getYouTubeEmbedUrl(selectedProduct.youtubeUrl) || ''} 
                    title="5MAXX Demonstration" 
                    frameBorder="0" 
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                    allowFullScreen
                  ></iframe>
                </div>
              )}

              <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5">
                <div className="flex items-center gap-2 mb-4 text-white/30 uppercase font-black text-[9px] tracking-widest">
                  <Info size={14} />
                  <span>Ficha Técnica 5MAXX</span>
                </div>
                <p className="text-white/60 text-sm leading-relaxed font-light">
                  {selectedProduct.description}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-white/5 p-4 rounded-2xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">NCM</p>
                  <p className="text-white text-xs font-mono">{selectedProduct.ncm}</p>
                </div>
                <div className="bg-white/5 p-4 rounded-2xl border border-white/5 text-center">
                  <p className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em] mb-1">Linha</p>
                  <p className="text-white text-xs font-mono">{selectedProduct.category}</p>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setSelectedProduct(null)}
              className="w-full mt-10 py-5 bg-white text-black font-black text-xs uppercase tracking-[0.4em] rounded-2xl transition-all"
            >
              Voltar ao Catálogo
            </button>
          </div>
        </div>
      )}

      {isScanning && <Scanner onScan={handleScanSuccess} onClose={() => setIsScanning(false)} />}
    </div>
  );
};

export default CatalogApp;

import React, { useState, useRef } from 'react';
import { Package, QrCode, Plus, LogOut, Download, Edit2, Trash2, X, Image as ImageIcon, Menu, Youtube, Tag } from 'lucide-react';
import { Product } from '../types';

interface AdminDashboardProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ products, setProducts, onLogout }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [showQrModal, setShowQrModal] = useState<Product | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const formRef = useRef<HTMLFormElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const categories = ['Espatulas', 'Estiletes', 'Feltros'];

  const handleEdit = (product: Product) => {
    setEditingProduct(product);
    setImagePreview(product.imageUrl);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Excluir este item permanentemente?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formRef.current) return;

    const formData = new FormData(formRef.current);
    const productData: Partial<Product> = {
      name: formData.get('name') as string,
      sku: formData.get('sku') as string,
      category: formData.get('category') as string,
      ncm: formData.get('ncm') as string,
      price: parseFloat(formData.get('price') as string) || 0,
      stock: parseInt(formData.get('stock') as string) || 0,
      description: formData.get('description') as string,
      youtubeUrl: formData.get('youtubeUrl') as string,
      imageUrl: imagePreview || `https://picsum.photos/seed/${Math.random()}/400/400`,
      barcode: formData.get('sku') as string
    };

    if (editingProduct) {
      setProducts(prev => prev.map(p => 
        p.id === editingProduct.id ? { ...p, ...productData } as Product : p
      ));
    } else {
      const newProduct: Product = {
        ...productData,
        id: Math.random().toString(36).substr(2, 9),
      } as Product;
      setProducts(prev => [newProduct, ...prev]);
    }

    setShowModal(false);
    setEditingProduct(null);
    setImagePreview(null);
  };

  return (
    <div className="min-h-screen flex bg-zinc-950 text-white font-sans">
      <aside className={`bg-black border-r border-white/10 flex flex-col transition-all duration-500 shadow-2xl z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="p-8 flex items-center justify-between">
          {isSidebarOpen && (
            <div className="flex flex-col">
              <h1 className="text-3xl font-black italic tracking-tighter">5MAXX</h1>
              <span className="text-[8px] font-light tracking-[0.2em] uppercase opacity-40">Admin Center</span>
            </div>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-colors">
            <Menu size={20} className="text-white" />
          </button>
        </div>

        <nav className="flex-1 mt-10 space-y-2 px-4">
          <button className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all bg-white text-black font-black uppercase text-[10px] tracking-widest shadow-2xl`}>
            <Package size={20} />
            {isSidebarOpen && <span>Catálogo Global</span>}
          </button>
        </nav>

        <button 
          onClick={onLogout}
          className="m-6 p-5 flex items-center gap-4 text-white/30 hover:text-white transition-colors bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5"
        >
          <LogOut size={20} />
          {isSidebarOpen && <span className="text-[10px] font-bold uppercase tracking-widest">Sair</span>}
        </button>
      </aside>

      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-end mb-16">
          <div>
            <h2 className="text-6xl font-black italic tracking-tighter mb-4">5MAXX <span className="text-white/10 font-light">PANEL</span></h2>
            <div className="flex items-center gap-4">
               <div className="h-1 w-12 bg-white"></div>
               <p className="text-white/40 text-sm font-medium uppercase tracking-[0.2em]">Gestão de Soluções 5MAXX</p>
            </div>
          </div>

          <button 
            onClick={() => { setEditingProduct(null); setImagePreview(null); setShowModal(true); }}
            className="bg-white text-black px-10 py-5 rounded-2xl flex items-center gap-3 hover:scale-105 transition-all shadow-2xl font-black text-xs uppercase tracking-widest active:scale-95"
          >
            <Plus size={20} />
            Novo Registro
          </button>
        </header>

        <div className="bg-zinc-900/40 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-inner backdrop-blur-md">
          <table className="w-full text-left">
            <thead className="bg-black/50 border-b border-white/10">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">SKU</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Produto</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30 text-right">Controles</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {products.length === 0 ? (
                <tr><td colSpan={4} className="p-20 text-center text-white/10 uppercase font-black text-xs tracking-widest">Aguardando novos SKUs...</td></tr>
              ) : products.map((p) => (
                <tr key={p.id} className="hover:bg-white/[0.02] transition-colors group">
                  <td className="px-8 py-6">
                    <span className="text-xs font-mono font-bold text-white/80 bg-white/5 px-3 py-1.5 rounded-lg border border-white/10">{p.sku}</span>
                  </td>
                  <td className="px-8 py-6">
                    <span className="text-[10px] font-black uppercase text-white/40">{p.category}</span>
                  </td>
                  <td className="px-8 py-6 flex items-center gap-6">
                    <img src={p.imageUrl} className="w-16 h-16 rounded-2xl object-cover bg-black border border-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                      <p className="font-black text-lg italic text-white uppercase">{p.name}</p>
                      <p className="text-[10px] text-white/30 font-bold tracking-widest uppercase">NCM: {p.ncm}</p>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex gap-3 justify-end items-center">
                      <button onClick={() => setShowQrModal(p)} className="p-3 text-white/20 hover:text-white hover:bg-white/10 rounded-xl transition-all"><QrCode size={20} /></button>
                      <button onClick={() => handleEdit(p)} className="p-3 text-white/20 hover:text-white hover:bg-white/10 rounded-xl transition-all"><Edit2 size={20} /></button>
                      <button onClick={() => handleDelete(p.id)} className="p-3 text-white/20 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={20} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-8">
           <form ref={formRef} onSubmit={handleSave} className="bg-zinc-950 border border-white/10 rounded-[3.5rem] w-full max-w-2xl shadow-2xl p-12 overflow-y-auto max-h-[90vh]">
              <div className="flex justify-between items-center mb-10">
                <div className="flex items-center gap-4">
                   <div className="w-12 h-1 bg-white"></div>
                   <h3 className="text-3xl font-black italic uppercase tracking-tighter">
                     {editingProduct ? 'Editar Registro' : 'Novo SKU 5MAXX'}
                   </h3>
                </div>
                <button type="button" onClick={() => setShowModal(false)} className="text-white/20 hover:text-white"><X size={32}/></button>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="col-span-2">
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-white/10 rounded-[2.5rem] cursor-pointer hover:border-white/30 hover:bg-white/5 transition-all overflow-hidden relative group"
                  >
                    {imagePreview ? (
                      <img src={imagePreview} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                    ) : (
                      <div className="text-center opacity-30 group-hover:opacity-100 transition-opacity">
                        <ImageIcon className="w-12 h-12 mb-4 mx-auto" />
                        <p className="text-[10px] font-black uppercase tracking-[0.3em]">Upload Imagem</p>
                      </div>
                    )}
                    <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageChange} />
                  </div>
                </div>

                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">Nome do Produto</label>
                  <input name="name" type="text" required defaultValue={editingProduct?.name} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-lg font-bold italic" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">Categoria</label>
                  <select name="category" defaultValue={editingProduct?.category} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-sm font-bold uppercase tracking-widest text-white appearance-none">
                    {categories.map(cat => <option key={cat} value={cat} className="bg-zinc-900">{cat}</option>)}
                  </select>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">SKU</label>
                  <input name="sku" type="text" required defaultValue={editingProduct?.sku} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white font-mono" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">NCM</label>
                  <input name="ncm" type="text" required defaultValue={editingProduct?.ncm} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white font-mono" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2 flex items-center gap-2">YouTube URL</label>
                  <input name="youtubeUrl" type="url" defaultValue={editingProduct?.youtubeUrl} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-sm" />
                </div>

                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">Descrição Técnica</label>
                  <textarea name="description" defaultValue={editingProduct?.description} className="w-full bg-white/5 border border-white/10 rounded-[2rem] p-6 h-40 outline-none resize-none focus:border-white text-white/60"></textarea>
                </div>
              </div>

              <div className="flex gap-6 mt-12">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 text-white/20 font-black uppercase text-xs tracking-[0.4em]">Cancelar</button>
                <button type="submit" className="flex-[2] bg-white text-black py-6 rounded-2xl font-black text-xs uppercase tracking-[0.4em] shadow-2xl active:scale-95 transition-all">
                  {editingProduct ? 'Salvar' : 'Confirmar'}
                </button>
              </div>
           </form>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

