                      <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60"></div>
                      <div className="absolute bottom-8 left-8 right-8">
                         <div className="bg-white/10 backdrop-blur-md border border-white/20 p-6 rounded-3xl">
                            <p className="text-[10px] font-black uppercase tracking-widest text-white mb-2">Simulação 5MAXX AI</p>
                            <p className="text-white/60 text-[10px] leading-relaxed uppercase font-bold tracking-tight">Transformando visões em realidade com a melhor tecnologia de adesivos do mercado.</p>
