                   <div className="mt-10 grid grid-cols-2 gap-4">
                      <button 
                        onClick={generateWrappingIdea}
                        className="flex items-center justify-center gap-3 bg-zinc-900 border border-white/10 text-white font-black py-5 rounded-2xl text-[10px] uppercase tracking-widest hover:bg-zinc-800 transition-all active:scale-95"
                      >
                        <RefreshCw size={16} /> Nova Ideia
