                      <img src={generatedIdea} alt="AI Generated Concept" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60"></div>
                      <div className="absolute bottom-8 left-8 right-8">
                         <div className="bg-white/10 backdrop-blur-md border border-white/20 p-6 rounded-3xl">
                            <p className="text-[10px] font-black uppercase tracking-widest text-white mb-2">Simulação 5MAXX AI</p>
                            <p className="text-white/60 text-[10px] leading-relaxed uppercase font-bold tracking-tight">Transformando visões em realidade com a melhor tecnologia de adesivos do mercado.</p>
                         </div>
                      </div>
                   </div>

                   <div className="mt-10 grid grid-cols-2 gap-4">
                      <button 
                        onClick={generateWrappingIdea}
                        className="flex items-center justify-center gap-3 bg-zinc-900 border border-white/10 text-white font-black py-5 rounded-2xl text-[10px] uppercase tracking-widest hover:bg-zinc-800 transition-all active:scale-95"
                      >
                        <RefreshCw size={16} /> Nova Ideia
                      </button>
                      <button 
                        className="flex items-center justify-center gap-3 bg-white text-black font-black py-5 rounded-2xl text-[10px] uppercase tracking-widest hover:bg-zinc-200 transition-all active:scale-95 shadow-xl shadow-white/5"
                        onClick={() => {
                          const link = document.createElement('a');
                          link.href = generatedIdea;
                          link.download = `5MAXX-AI-Inspiration-${Date.now()}.png`;
                          link.click();
