                        <Download size={16} /> Salvar
                      </button>
                   </div>
                </div>
              ) : null}
           </div>
        </div>
      )}

      {/* Full Specification Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[110] flex items-end">
          <div className="bg-zinc-950 w-full max-w-md mx-auto rounded-t-[3.5rem] p-10 animate-slide-up shadow-2xl border-t border-white/10 overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="flex justify-center mb-10">
              <div className="w-20 h-1.5 bg-white/10 rounded-full"></div>
            </div>

            <div className="flex gap-8 mb-12 items-start">
              <div className="relative">
                <img src={selectedProduct.imageUrl} className="w-36 h-36 rounded-[2.5rem] object-cover shadow-2xl bg-black border border-white/10" />
                <div className="absolute -bottom-2 -right-2 bg-white text-black p-2.5 rounded-2xl shadow-xl">
                   <Box size={20} />
                </div>
              </div>
              <div className="flex-1 pt-2">
                <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.4em] mb-3">{selectedProduct.sku}</p>
                <h3 className="text-3xl font-black text-white italic leading-none uppercase mb-6 tracking-tighter">{selectedProduct.name}</h3>
                <div className="inline-flex items-center px-4 py-2 bg-white text-black rounded-2xl shadow-lg">
                  <span className="text-[9px] font-black uppercase tracking-widest">{selectedProduct.category}</span>
                </div>
              </div>
            </div>

            <div className="space-y-8">
              {getYouTubeEmbedUrl(selectedProduct.youtubeUrl) && (
                <div className="rounded-[2.5rem] overflow-hidden border-2 border-white/5 aspect-video shadow-2xl bg-black">
                  <iframe 
                    width="100%" 
                    height="100%" 
                    src={getYouTubeEmbedUrl(selectedProduct.youtubeUrl) || ''} 
                    title="5MAXX Video Review" 
                    frameBorder="0" 
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                    allowFullScreen
                  ></iframe>
                </div>
              )}

              <div className="bg-white/5 p-8 rounded-[2.5rem] border border-white/10">
                <div className="flex items-center gap-3 mb-6 text-white/30 uppercase font-black text-[10px] tracking-[0.3em]">
                  <Info size={16} />
                  <span>Especificações Técnicas</span>
                </div>
                <p className="text-white/70 text-base leading-relaxed font-light">
                  {selectedProduct.description}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-5">
                <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5 text-center">
                  <p className="text-[9px] font-black text-white/20 uppercase tracking-[0.3em] mb-2">Classificação Fiscal</p>
                  <p className="text-white text-sm font-mono font-bold">{selectedProduct.ncm}</p>
                </div>
                <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5 text-center">
                  <p className="text-[9px] font-black text-white/20 uppercase tracking-[0.3em] mb-2">Linha Produtiva</p>
                  <p className="text-white text-sm font-bold uppercase tracking-widest">{selectedProduct.category}</p>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setSelectedProduct(null)}
              className="w-full mt-12 py-6 bg-white text-black font-black text-sm uppercase tracking-[0.5em] rounded-3xl shadow-2xl active:scale-95 transition-all"
            >
              Concluir Consulta
            </button>
          </div>
        </div>
      )}

      {isScanning && <Scanner onScan={handleScanSuccess} onClose={() => setIsScanning(false)} />}
    </div>
  );
};

export default CatalogApp;

