              <div className="flex-1 pt-2">
                <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.4em] mb-3">{selectedProduct.sku}</p>
                <h3 className="text-3xl font-black text-white italic leading-none uppercase mb-6 tracking-tighter">{selectedProduct.name}</h3>
                <div className="inline-flex items-center px-4 py-2 bg-white text-black rounded-2xl shadow-lg">
                  <span className="text-[9px] font-black uppercase tracking-widest">{selectedProduct.category}</span>
