];

const PROMPT_CATEGORIES = [
  { id: 'car', name: 'Carros', icon: <Car size={24} />, prompt: "A luxury electric supercar wrapped in a stunning iridescent deep purple and teal chameleon vinyl finish, parked in a minimalist showroom, 8k resolution, cinematic lighting." },
  { id: 'truck', name: 'Caminhões', icon: <Truck size={24} />, prompt: "A custom heavy-duty pickup truck wrapped in a rugged matte desert camouflage pattern, off-road setting during sunset, dramatic lighting, high detail." },
  { id: 'van', name: 'Vans', icon: <Bus size={24} />, prompt: "A large commercial delivery van wrapped in a vibrant geometric architectural design for a high-end furniture brand, urban street background, professional branding photography." },
  { id: 'kitchen', name: 'Cozinhas', icon: <Utensils size={24} />, prompt: "A modern luxury kitchen featuring cabinets wrapped in a premium brushed stainless steel and dark oak wood-grain vinyl, interior design catalog photography style." },
  { id: 'office', name: 'Escritórios', icon: <Briefcase size={24} />, prompt: "A high-tech corporate office wall decorated with a sophisticated 3D embossed geometric pattern wrap, soft architectural spotlighting, minimalist furniture." },
];

const CatalogApp: React.FC<CatalogAppProps> = ({ products, onLogout }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  // AI Generation States
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedIdea, setGeneratedIdea] = useState<string | null>(null);
  const [showAiModal, setShowAiModal] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [aiSelectionStep, setAiSelectionStep] = useState(true);

  // Quiz States
  const [showQuizModal, setShowQuizModal] = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);

  const loadingMessages = [
    "Sintonizando com a criatividade 5MAXX...",
    "Selecionando texturas premium...",
    "Preparando superfícies específicas...",
    "Aplicando adesivo virtual com precisão...",
    "Ajustando reflexos e iluminação..."
  ];

  const categories = ['Espatulas', 'Estiletes', 'Feltros', 'Acessórios'];

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         p.sku.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory ? p.category === selectedCategory : true;
    return matchesSearch && matchesCategory;
  });

  const handleScanSuccess = (code: string) => {
    const found = products.find(p => p.sku === code || p.barcode === code);
    if (found) {
      setSelectedProduct(found);
    }
    setIsScanning(false);
  };

  const generateWrappingIdea = async (promptText: string) => {
    setIsGenerating(true);
    setAiSelectionStep(false);
    setGeneratedIdea(null);

    let messageIndex = 0;
    setLoadingMessage(loadingMessages[0]);
    const interval = setInterval(() => {
      messageIndex = (messageIndex + 1) % loadingMessages.length;
      setLoadingMessage(loadingMessages[messageIndex]);
    }, 2500);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: promptText }]
        },
        config: {
          imageConfig: {
            aspectRatio: "9:16"
          }
        }
      });

      let foundImage = null;
      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            foundImage = `data:image/png;base64,${part.inlineData.data}`;
            break;
          }
        }
      }

      if (foundImage) {
        setGeneratedIdea(foundImage);
      } else {
        throw new Error("No image data received");
      }
    } catch (error) {
      console.error("AI Generation Error:", error);
      alert("Erro na geração. Verifique sua conexão ou tente novamente em instantes.");
      setShowAiModal(false);
      setAiSelectionStep(true);
    } finally {
      clearInterval(interval);
      setIsGenerating(false);
    }
  };

  const handleQuizAnswer = (idx: number) => {
    if (isAnswered) return;
    setSelectedOption(idx);
    setIsAnswered(true);
    if (idx === QUIZ_QUESTIONS[currentQuestion].correct) {
      setScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    if (currentQuestion + 1 < QUIZ_QUESTIONS.length) {
      setCurrentQuestion(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      setShowResult(true);
    }
  };

  const resetQuiz = () => {
    setCurrentQuestion(0);
    setScore(0);
    setShowResult(false);
    setSelectedOption(null);
    setIsAnswered(false);
  };

  const getYouTubeEmbedUrl = (url?: string) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|\&v=)([^#\&\?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? `https://www.youtube.com/embed/${match[2]}` : null;
  };

  const getCategoryIcon = (cat: string) => {
    switch (cat) {
      case 'Espatulas': return <LayoutGrid size={20} />;
      case 'Estiletes': return <Scissors size={20} />;
      case 'Feltros': return <Layers size={20} />;
      case 'Acessórios': return <Tag size={20} />;
      default: return <Box size={20} />;
    }
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-black flex flex-col relative pb-24 overflow-x-hidden border-x border-white/5 font-sans">
      {/* Category Sidebar/Menu Overlay */}
      {isMenuOpen && (
        <div className="fixed inset-0 z-[100] flex">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)}></div>
          <div className="relative w-72 bg-zinc-950 border-r border-white/10 h-full p-8 animate-slide-right flex flex-col">
             <div className="flex justify-between items-center mb-12">
               <div className="flex flex-col">
                  <h1 className="text-3xl font-black italic text-white tracking-tighter">5MAXX</h1>
                  <span className="text-[7px] font-light tracking-[0.4em] uppercase opacity-40">Innovating Beyond</span>
               </div>
               <button onClick={() => setIsMenuOpen(false)} className="text-white/40"><X size={24} /></button>
             </div>

             <div className="space-y-4">
               <p className="text-[10px] font-black text-white/20 uppercase tracking-[0.3em] mb-4 border-b border-white/5 pb-2">Departamentos</p>
               <button 
                 onClick={() => { setSelectedCategory(null); setIsMenuOpen(false); }}
                 className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all ${!selectedCategory ? 'bg-white text-black font-black shadow-xl shadow-white/10' : 'text-white/60 hover:bg-white/5'}`}
               >
                 <LayoutGrid size={20} />
                 <span className="text-xs uppercase tracking-widest font-bold">Todos os Itens</span>
               </button>

               {categories.map(cat => (
                 <button 
                   key={cat}
                   onClick={() => { setSelectedCategory(cat); setIsMenuOpen(false); }}
                   className={`w-full flex items-center gap-4 p-4 rounded-2xl transition-all ${selectedCategory === cat ? 'bg-white text-black font-black shadow-xl shadow-white/5' : 'text-white/60 hover:bg-white/5'}`}
                 >
                   {getCategoryIcon(cat)}
                   <span className="text-xs uppercase tracking-widest font-bold">{cat}</span>
                 </button>
               ))}
             </div>

             <div className="mt-auto pt-8 border-t border-white/10">
                <button onClick={onLogout} className="w-full py-4 text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white flex items-center justify-center gap-2 border border-white/5 rounded-xl hover:bg-white/5 transition-all">
                  <X size={14} /> Encerrar Sessão
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-black text-white p-7 sticky top-0 z-40 border-b border-white/10">
        <div className="flex justify-between items-center mb-8">
          <button onClick={() => setIsMenuOpen(true)} className="p-2 -ml-2 text-white hover:opacity-70 transition-opacity">
            <Menu size={28} />
          </button>
          <div className="flex flex-col items-center">
             <h1 className="text-4xl font-black italic tracking-tighter leading-none bg-gradient-to-br from-white via-zinc-200 to-zinc-500 bg-clip-text text-transparent">5MAXX</h1>
             <span className="text-[7px] font-light tracking-[0.4em] uppercase opacity-40 mt-1">Innovating Beyond</span>
          </div>
          <button onClick={() => setIsScanning(true)} className="p-2 -mr-2 text-white hover:opacity-70 transition-opacity">
            <Camera size={26} />
          </button>
        </div>

        <div className="relative group">
          <input 
            type="text" 
            placeholder="Pesquisar por SKU ou Nome..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-white border-2 border-transparent rounded-2xl py-4 px-12 text-sm text-black font-bold placeholder-zinc-500 focus:ring-4 focus:ring-zinc-500/10 focus:border-zinc-300 outline-none transition-all shadow-2xl"
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400 group-focus-within:text-black transition-colors" size={18} />
          {searchTerm && (
            <button onClick={() => setSearchTerm('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-zinc-300 hover:text-black">
              <X size={16} />
            </button>
          )}
        </div>

        {selectedCategory && (
          <div className="mt-5 flex items-center gap-2 overflow-x-auto pb-1 no-scrollbar">
            <span className="text-[9px] font-black uppercase tracking-widest text-white/40 whitespace-nowrap">Filtrando:</span>
            <button 
              onClick={() => setSelectedCategory(null)}
              className="bg-zinc-800 px-4 py-2 rounded-full text-[9px] font-black uppercase flex items-center gap-2 border border-white/10 hover:bg-zinc-700 transition-colors whitespace-nowrap"
            >
              {selectedCategory} <X size={12} className="opacity-50" />
            </button>
          </div>
        )}
      </header>

      {/* Main Catalog View */}
      <main className="p-6 flex-1 bg-gradient-to-b from-black to-zinc-950">
        <section>
          <div className="flex justify-between items-center mb-8 px-2">
            <h2 className="font-black text-white flex items-center gap-2 uppercase tracking-[0.2em] text-[10px] opacity-40">
              {selectedCategory ? `Linha ${selectedCategory}` : 'Toda a Coleção'}
              <span className="w-8 h-[1px] bg-white/20 ml-2"></span>
            </h2>
            <span className="text-[9px] font-bold text-white/20 uppercase">{filteredProducts.length} itens</span>
          </div>

          <div className="grid grid-cols-1 gap-6">
            {filteredProducts.map(p => (
              <div 
                key={p.id} 
                onClick={() => setSelectedProduct(p)}
                className="bg-zinc-900/40 p-5 rounded-[2.5rem] border border-white/5 flex gap-5 items-center hover:bg-zinc-900 transition-all cursor-pointer group shadow-lg active:scale-95"
              >
                <div className="relative">
                  <img src={p.imageUrl} className="w-24 h-24 aspect-square object-cover rounded-[1.5rem] bg-black border border-white/5 group-hover:scale-105 transition-transform" alt={p.name} />
                </div>
                <div className="flex-1 overflow-hidden">
                  <p className="text-[9px] font-black text-white/30 mb-1.5 uppercase tracking-[0.2em] truncate">{p.sku}</p>
                  <p className="text-lg font-black text-white uppercase italic leading-tight group-hover:text-amber-500 transition-colors truncate">{p.name}</p>
                  <div className="mt-4 flex items-center gap-3">
                     <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-full group-hover:bg-white group-hover:text-black transition-all">
                        <span className="text-[9px] font-black uppercase tracking-widest">Ficha Técnica</span>
                        <ChevronRight size={12} className="opacity-40 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all" />
                     </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-black/95 backdrop-blur-2xl border-t border-white/10 flex justify-center gap-12 p-6 z-50 rounded-t-[2.5rem] shadow-[0_-20px_50px_rgba(0,0,0,0.5)]">
        {/* Quiz Button */}
        <button 
          onClick={() => { resetQuiz(); setShowQuizModal(true); }}
          className="flex flex-col items-center group relative"
        >
          <div className="w-16 h-16 bg-gradient-to-br from-zinc-700 via-zinc-800 to-black rounded-full flex items-center justify-center text-white shadow-xl group-active:scale-90 transition-transform border-2 border-white/10 overflow-hidden">
            <Trophy size={28} className="text-amber-500" />
          </div>
          <span className="text-[8px] font-black uppercase tracking-[0.4em] text-white/40 mt-3 group-hover:text-white transition-colors">Quiz Master</span>
        </button>

        {/* AI Ideas Button */}
        <button 
          onClick={() => { setGeneratedIdea(null); setAiSelectionStep(true); setShowAiModal(true); }}
          className="flex flex-col items-center group relative"
        >
          <div className="w-16 h-16 bg-gradient-to-br from-amber-400 via-amber-600 to-amber-900 rounded-full flex items-center justify-center text-white shadow-[0_0_30px_rgba(251,191,36,0.3)] group-active:scale-90 transition-transform relative z-10 border-2 border-white/20 overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
            <Sparkles size={28} className="relative z-10 animate-pulse" />
          </div>
          <span className="text-[8px] font-black uppercase tracking-[0.4em] text-amber-500 mt-3 opacity-90 group-hover:opacity-100 transition-opacity">Ideias IA</span>
          <div className="absolute -inset-2 bg-amber-500/10 blur-xl rounded-full opacity-50 group-hover:opacity-100 transition-opacity"></div>
        </button>
      </nav>

      {/* Quiz Modal */}
      {showQuizModal && (
        <div className="fixed inset-0 bg-black/98 backdrop-blur-3xl z-[200] flex flex-col items-center justify-center p-6">
           <button 
             onClick={() => setShowQuizModal(false)}
             className="absolute top-10 right-8 text-white/40 hover:text-white p-2 rounded-full border border-white/5 transition-all"
           >
             <X size={32} />
           </button>

           <div className="w-full max-w-sm flex flex-col items-center">
              {!showResult ? (
                <div className="w-full animate-slide-up">
                  <div className="text-center mb-10">
                    <div className="inline-flex items-center gap-2 px-4 py-2 bg-amber-500/10 border border-amber-500/20 rounded-full mb-6">
                      <HelpCircle size={14} className="text-amber-500" />
                      <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest">Desafio 5MAXX</span>
                    </div>
                    <div className="flex justify-between items-end mb-4 px-2">
                       <h3 className="text-white/40 text-[9px] font-black uppercase tracking-[0.4em]">Questão {currentQuestion + 1} de {QUIZ_QUESTIONS.length}</h3>
                       <div className="h-1.5 w-32 bg-white/5 rounded-full overflow-hidden">
                          <div 
                            className="h-full bg-amber-500 transition-all duration-500" 
                            style={{ width: `${((currentQuestion + 1) / QUIZ_QUESTIONS.length) * 100}%` }}
                          ></div>
                       </div>
                    </div>
                    <h2 className="text-2xl font-black text-white italic leading-tight uppercase tracking-tighter">
                      {QUIZ_QUESTIONS[currentQuestion].question}
                    </h2>
                  </div>

                  <div className="space-y-4">
                    {QUIZ_QUESTIONS[currentQuestion].options.map((opt, idx) => {
                      let bgColor = "bg-white/5 border-white/10 text-white/70";
                      if (isAnswered) {
                        if (idx === QUIZ_QUESTIONS[currentQuestion].correct) {
                          bgColor = "bg-green-500/20 border-green-500 text-green-400";
                        } else if (idx === selectedOption) {
                          bgColor = "bg-red-500/20 border-red-500 text-red-400";
                        }
                      } else if (idx === selectedOption) {
                        bgColor = "bg-amber-500/10 border-amber-500 text-white";
                      }

                      return (
                        <button 
                          key={idx}
                          onClick={() => handleQuizAnswer(idx)}
                          disabled={isAnswered}
                          className={`w-full p-6 rounded-3xl border text-left transition-all relative group overflow-hidden ${bgColor}`}
                        >
                          <span className="relative z-10 font-bold text-sm leading-relaxed">{opt}</span>
                          {isAnswered && idx === QUIZ_QUESTIONS[currentQuestion].correct && (
                            <CheckCircle2 size={18} className="absolute right-6 top-1/2 -translate-y-1/2 text-green-500" />
                          )}
                          {isAnswered && idx === selectedOption && idx !== QUIZ_QUESTIONS[currentQuestion].correct && (
                            <AlertCircle size={18} className="absolute right-6 top-1/2 -translate-y-1/2 text-red-500" />
                          )}
                        </button>
                      );
                    })}
                  </div>

                  {isAnswered && (
                    <button 
                      onClick={nextQuestion}
                      className="w-full mt-10 py-6 bg-white text-black font-black uppercase tracking-[0.4em] text-xs rounded-2xl shadow-2xl animate-pulse"
                    >
                      {currentQuestion + 1 === QUIZ_QUESTIONS.length ? 'Ver Resultado' : 'Próxima Questão'}
                    </button>
                  )}
                </div>
              ) : (
                <div className="text-center animate-slide-up">
                   <div className="relative mb-12 flex justify-center">
                      <div className="absolute inset-0 bg-amber-500/10 blur-[100px] rounded-full"></div>
                      <div className="w-40 h-40 bg-gradient-to-br from-amber-400 to-amber-900 rounded-full flex items-center justify-center shadow-2xl relative">
                         <Trophy size={80} className="text-white drop-shadow-2xl" />
                      </div>
                   </div>
                   <h2 className="text-4xl font-black italic text-white uppercase tracking-tighter mb-4">Mestre do Envelopamento</h2>
                   <p className="text-white/40 text-xs font-bold uppercase tracking-[0.4em] mb-12">Você acertou {score} de {QUIZ_QUESTIONS.length} questões</p>

                   <div className="space-y-4">
                      <button 
                        onClick={resetQuiz}
                        className="w-full py-6 bg-white text-black font-black uppercase tracking-[0.4em] text-xs rounded-2xl shadow-2xl"
                      >
                        Tentar Novamente
                      </button>
                      <button 
                        onClick={() => setShowQuizModal(false)}
                        className="w-full py-6 bg-transparent border border-white/10 text-white/40 font-black uppercase tracking-[0.4em] text-xs rounded-2xl"
                      >
                        Voltar ao Início
                      </button>
                   </div>
                </div>
              )}
           </div>
        </div>
      )}

      {/* AI Inspiration Modal */}
      {showAiModal && (
        <div className="fixed inset-0 bg-black/98 backdrop-blur-3xl z-[200] flex flex-col items-center justify-center p-6 overflow-y-auto">
           <button 
             onClick={() => setShowAiModal(false)}
             className="absolute top-10 right-8 text-white/40 hover:text-white p-2 rounded-full border border-white/5 transition-all"
           >
             <X size={32} />
           </button>

           <div className="w-full max-w-sm flex flex-col items-center py-10">
              {aiSelectionStep ? (
                <div className="w-full animate-slide-up flex flex-col items-center">
                   <div className="text-center mb-10">
                      <div className="inline-flex items-center gap-2 px-4 py-2 bg-amber-500/10 border border-amber-500/20 rounded-full mb-6">
                         <Sparkles size={14} className="text-amber-500" />
                         <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest">Estúdio 5MAXX AI</span>
                      </div>
                      <h2 className="text-3xl font-black italic text-white uppercase tracking-tighter leading-tight">Escolha seu Estilo de Visualização</h2>
                      <p className="text-white/40 text-[10px] font-bold uppercase tracking-[0.3em] mt-4">Nossa IA criará um conceito exclusivo para você</p>
                   </div>

                   <div className="grid grid-cols-1 gap-4 w-full">
                      {PROMPT_CATEGORIES.map(cat => (
                        <button 
                          key={cat.id}
                          onClick={() => generateWrappingIdea(cat.prompt)}
                          className="w-full flex items-center gap-6 p-6 rounded-3xl bg-white/5 border border-white/10 hover:bg-white hover:text-black hover:scale-[1.02] transition-all group overflow-hidden relative"
                        >
                          <div className="p-4 bg-white/5 rounded-2xl group-hover:bg-black/5 transition-colors">
                             {cat.icon}
                          </div>
                          <div className="flex flex-col items-start">
                             <span className="text-xs font-black uppercase tracking-widest leading-none">{cat.name}</span>
                             <span className="text-[8px] font-bold uppercase tracking-[0.2em] opacity-40 group-hover:opacity-60 mt-2">Conceito Premium</span>
                          </div>
                          <ChevronRight size={18} className="ml-auto opacity-20 group-hover:opacity-100 group-hover:translate-x-1 transition-all" />
                        </button>
                      ))}
                   </div>
                </div>
              ) : isGenerating ? (
                <div className="flex flex-col items-center text-center py-20">
                   <div className="relative mb-12">
                      <div className="absolute inset-0 bg-amber-500/20 blur-[80px] rounded-full animate-pulse"></div>
                      <Loader2 className="w-24 h-24 text-amber-500 animate-spin stroke-[1]" />
                      <Sparkles className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white/40 w-8 h-8" />
                   </div>
                   <h3 className="text-2xl font-black italic uppercase tracking-tighter text-white mb-4 animate-pulse">Criando Arte Digital</h3>
                   <p className="text-white/40 text-xs font-bold uppercase tracking-[0.4em] max-w-[250px] leading-loose">{loadingMessage}</p>
                </div>
              ) : generatedIdea ? (
                <div className="w-full flex flex-col animate-slide-up">
                   <div className="flex flex-col items-center mb-8">
                      <div className="flex items-center gap-3 mb-2">
                         <Sparkles className="text-amber-500" size={20} />
                         <h3 className="text-2xl font-black italic uppercase tracking-tighter text-white">Inspirado pela 5MAXX</h3>
                      </div>
                      <p className="text-white/40 text-[9px] font-bold uppercase tracking-[0.3em]">Conceito de Envelopamento Premium</p>
                   </div>

