              <div className="grid grid-cols-2 gap-5">
                <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5 text-center">
                  <p className="text-[9px] font-black text-white/20 uppercase tracking-[0.3em] mb-2">Classificação Fiscal</p>
                  <p className="text-white text-sm font-mono font-bold">{selectedProduct.ncm}</p>
                </div>
                <div className="bg-white/5 p-6 rounded-[2rem] border border-white/5 text-center">
                  <p className="text-[9px] font-black text-white/20 uppercase tracking-[0.3em] mb-2">Linha Produtiva</p>
                  <p className="text-white text-sm font-bold uppercase tracking-widest">{selectedProduct.category}</p>
                </div>
              </div>

              <button 
                onClick={() => { setSelectedProduct(null); setShowMapModal(true); }}
                className="w-full flex items-center justify-center gap-3 py-6 bg-amber-500 text-black font-black rounded-3xl text-sm uppercase tracking-widest active:scale-95 transition-all shadow-xl shadow-amber-500/10"
              >
                <MapPin size={18} />
                Onde Encontrar este Item
              </button>
            </div>

            <button 
              onClick={() => setSelectedProduct(null)}
              className="w-full mt-6 py-6 border border-white/10 text-white/30 font-black text-sm uppercase tracking-[0.5em] rounded-3xl hover:text-white transition-all active:scale-95"
            >
              Concluir Consulta
            </button>
          </div>
        </div>
      )}

      {isScanning && <Scanner onScan={handleScanSuccess} onClose={() => setIsScanning(false)} />}
    </div>
  );
};

export default CatalogApp;

import React, { useState, useEffect } from 'react';
import { Camera, Search, X, Info, ChevronRight, Box, Menu, LayoutGrid, Layers, Scissors, Tag, Sparkles, Loader2, RefreshCw, Download, Trophy, CheckCircle2, AlertCircle, HelpCircle, Car, Truck, Bus, Utensils, Briefcase, MapPin } from 'lucide-react';
import { Product } from '../types';
import { GoogleGenAI } from "@google/genai";
import Scanner from './Scanner';

interface CatalogAppProps {
  products: Product[];
  onLogout: () => void;
}

interface QuizQuestion {
  question: string;
  options: string[];
  correct: number;
}

const QUIZ_QUESTIONS: QuizQuestion[] = [
  {
    question: "Para que serve o soprador térmico no envelopamento?",
    options: [
      "Limpar a superfície antes da aplicação",
      "Moldar o adesivo e remover a memória do PVC",
