              ) : generatedIdea ? (
                <div className="w-full flex flex-col animate-slide-up">
                   <div className="flex flex-col items-center mb-8">
                      <div className="flex items-center gap-3 mb-2">
                         <Sparkles className="text-amber-500" size={20} />
                         <h3 className="text-2xl font-black italic uppercase tracking-tighter text-white">Inspirado pela 5MAXX</h3>
                      </div>
                      <p className="text-white/40 text-[9px] font-bold uppercase tracking-[0.3em]">Conceito de Envelopamento Premium</p>
                   </div>

                   <div className="relative rounded-[3rem] overflow-hidden border border-white/10 shadow-2xl aspect-[9/16] bg-zinc-900 group">
                      <img src={generatedIdea} alt="AI Generated Concept" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60"></div>
                      <div className="absolute bottom-8 left-8 right-8">
                         <div className="bg-white/10 backdrop-blur-md border border-white/20 p-6 rounded-3xl">
                            <p className="text-[10px] font-black uppercase tracking-widest text-white mb-2">Simulação 5MAXX AI</p>
                            <p className="text-white/60 text-[10px] leading-relaxed uppercase font-bold tracking-tight">Transformando visões em realidade com a melhor tecnologia de adesivos do mercado.</p>
                         </div>
                      </div>
                   </div>

                   <div className="mt-10 grid grid-cols-2 gap-4">
                      <button 
                        onClick={() => setAiSelectionStep(true)}
                        className="flex items-center justify-center gap-3 bg-zinc-900 border border-white/10 text-white font-black py-5 rounded-2xl text-[10px] uppercase tracking-widest hover:bg-zinc-800 transition-all active:scale-95"
                      >
                        <RefreshCw size={16} /> Novo Estilo
                      </button>
                      <button 
                        className="flex items-center justify-center gap-3 bg-white text-black font-black py-5 rounded-2xl text-[10px] uppercase tracking-widest hover:bg-zinc-200 transition-all active:scale-95 shadow-xl shadow-white/5"
                        onClick={() => {
                          const link = document.createElement('a');
                          link.href = generatedIdea;
                          link.download = `5MAXX-AI-Inspiration-${Date.now()}.png`;
                          link.click();
                        }}
                      >
                        <Download size={16} /> Salvar
                      </button>
                   </div>
                </div>
              ) : null}
           </div>
        </div>
      )}

      {/* Full Specification Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[110] flex items-end">
          <div className="bg-zinc-950 w-full max-w-md mx-auto rounded-t-[3.5rem] p-10 animate-slide-up shadow-2xl border-t border-white/10 overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="flex justify-center mb-10">
              <div className="w-20 h-1.5 bg-white/10 rounded-full"></div>
            </div>

            <div className="flex gap-8 mb-12 items-start">
              <div className="relative">
                <img src={selectedProduct.imageUrl} className="w-36 h-36 rounded-[2.5rem] object-cover shadow-2xl bg-black border border-white/10" />
                <div className="absolute -bottom-2 -right-2 bg-white text-black p-2.5 rounded-2xl shadow-xl">
                   <Box size={20} />
                </div>
              </div>
              <div className="flex-1 pt-2">
                <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.4em] mb-3">{selectedProduct.sku}</p>
                <h3 className="text-3xl font-black text-white italic leading-none uppercase mb-6 tracking-tighter">{selectedProduct.nome}</h3>
                <div className="inline-flex items-center px-4 py-2 bg-white text-black rounded-2xl shadow-lg">
