import React, { useState, useRef } from 'react';
import { Package, QrCode, Plus, LogOut, Download, Edit2, Trash2, X, Image as ImageIcon, Menu, Youtube, Tag } from 'lucide-react';
import { Product } from '../types';

interface AdminDashboardProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ products, setProducts, onLogout }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [showQrModal, setShowQrModal] = useState<Product | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<File | undefined>(undefined);
  const formRef = useRef<HTMLFormElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const categories = ['Espatulas', 'Estiletes', 'Feltros', 'Acessórios'];

  const handleEdit = (product: Product) => {
    setEditingProduct(product);
    setImagePreview(product.imageUrl);
    setShowModal(true);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Excluir este item permanentemente?')) {
      setProducts(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formRef.current) return;

    const formData = new FormData(formRef.current);
    const productData: Partial<Product> = {
      nome: formData.get('nome') as string,
      sku: formData.get('sku') as string,
      categoria: formData.get('categoria') as string,
      ncm: formData.get('ncm') as string,
      preco: parseFloat(formData.get('preco') as string) || 0,
      estoque: parseInt(formData.get('estoque') as string) || 0,
      descricaoTecnica: formData.get('descricaoTecnica') as string,
      youtubeUrl: formData.get('youtubeUrl') as string,
      imageUrl: imagePreview || `https://picsum.photos/seed/${Math.random()}/400/400`,
      barcode: formData.get('sku') as string,
      imagem: selectedFile
    };

    if (editingProduct) {
      setProducts(prev => prev.map(p => 
        p.id === editingProduct.id ? { ...p, ...productData } as Product : p
      ));
    } else {
      const newProduct: Product = {
        ...productData,
        id: Math.random().toString(36).substr(2, 9),
      } as Product;
      setProducts(prev => [newProduct, ...prev]);
    }

    setShowModal(false);
    setEditingProduct(null);
    setImagePreview(null);
    setSelectedFile(undefined);
  };

  return (
    <div className="min-h-screen flex bg-zinc-950 text-white font-sans">
      <aside className={`bg-black border-r border-white/10 flex flex-col transition-all duration-500 shadow-2xl z-50 ${isSidebarOpen ? 'w-72' : 'w-24'}`}>
        <div className="p-8 flex items-center justify-between">
          {isSidebarOpen && (
            <div className="flex flex-col">
              <h1 className="text-3xl font-black italic tracking-tighter">5MAXX</h1>
              <span className="text-[8px] font-light tracking-[0.2em] uppercase opacity-40">Admin Center</span>
            </div>
          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-colors">
            <Menu size={20} className="text-white" />
          </button>
        </div>

        <nav className="flex-1 mt-10 space-y-2 px-4">
          <button className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all bg-white text-black font-black uppercase text-[10px] tracking-widest shadow-2xl`}>
            <Package size={20} />
            {isSidebarOpen && <span>Catálogo Global</span>}
          </button>
        </nav>

        <button 
          onClick={onLogout}
          className="m-6 p-5 flex items-center gap-4 text-white/30 hover:text-white transition-colors bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5"
        >
          <LogOut size={20} />
          {isSidebarOpen && <span className="text-[10px] font-bold uppercase tracking-widest">Sair</span>}
        </button>
      </aside>

      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-end mb-16">
          <div>
            <h2 className="text-6xl font-black italic tracking-tighter mb-4">5MAXX <span className="text-white/10 font-light">PANEL</span></h2>
            <div className="flex items-center gap-4">
               <div className="h-1 w-12 bg-white"></div>
               <p className="text-white/40 text-sm font-medium uppercase tracking-[0.2em]">Gestão de Soluções 5MAXX</p>
            </div>
          </div>

          <button 
            onClick={() => { setEditingProduct(null); setImagePreview(null); setShowModal(true); }}
            className="bg-white text-black px-10 py-5 rounded-2xl flex items-center gap-3 hover:scale-105 transition-all shadow-2xl font-black text-xs uppercase tracking-widest active:scale-95"
          >
            <Plus size={20} />
            Novo Registro
          </button>
        </header>

        <div className="bg-zinc-900/40 rounded-[2.5rem] border border-white/10 overflow-hidden shadow-inner backdrop-blur-md">
          <table className="w-full text-left">
            <thead className="bg-black/50 border-b border-white/10">
              <tr>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">SKU</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Categoria</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Produto</th>
                <th className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.3em] text-white/30 text-right">Controles</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {products.length === 0 ? (
                <tr><td colSpan={4} className="p-20 text-center text-white/10 uppercase font-black text-xs tracking-widest">Aguardando novos SKUs...</td></tr>
              ) : products.map((p) => (
                <tr key={p.id} className="hover:bg-white/[0.02] transition-colors group">
                  <td className="px-8 py-6">
                    <span className="text-xs font-mono font-bold text-white/80 bg-white/5 px-3 py-1.5 rounded-lg border border-white/10">{p.sku}</span>
                  </td>
                  <td className="px-8 py-6">
                    <span className="text-[10px] font-black uppercase text-white/40">{p.categoria}</span>
                  </td>
                  <td className="px-8 py-6 flex items-center gap-6">
                    <img src={p.imageUrl} className="w-16 h-16 rounded-2xl object-cover bg-black border border-white/10 group-hover:scale-110 transition-transform" />
                    <div>
                      <p className="font-black text-lg italic text-white uppercase">{p.nome}</p>
                      <p className="text-[10px] text-white/30 font-bold tracking-widest uppercase">NCM: {p.ncm}</p>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex gap-3 justify-end items-center">
                      <button onClick={() => setShowQrModal(p)} className="p-3 text-white/20 hover:text-white hover:bg-white/10 rounded-xl transition-all"><QrCode size={20} /></button>
                      <button onClick={() => handleEdit(p)} className="p-3 text-white/20 hover:text-white hover:bg-white/10 rounded-xl transition-all"><Edit2 size={20} /></button>
                      <button onClick={() => handleDelete(p.id)} className="p-3 text-white/20 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><Trash2 size={20} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-8">
           <form ref={formRef} onSubmit={handleSave} className="bg-zinc-950 border border-white/10 rounded-[3.5rem] w-full max-w-2xl shadow-2xl p-12 overflow-y-auto max-h-[90vh]">
              <div className="flex justify-between items-center mb-10">
                <div className="flex items-center gap-4">
                   <div className="w-12 h-1 bg-white"></div>
                   <h3 className="text-3xl font-black italic uppercase tracking-tighter">
                     {editingProduct ? 'Editar Registro' : 'Novo SKU 5MAXX'}
                   </h3>
                </div>
                <button type="button" onClick={() => setShowModal(false)} className="text-white/20 hover:text-white"><X size={32}/></button>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="col-span-2">
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex flex-col items-center justify-center w-full h-64 border-2 border-dashed border-white/10 rounded-[2.5rem] cursor-pointer hover:border-white/30 hover:bg-white/5 transition-all overflow-hidden relative group"
                  >
                    {imagePreview ? (
                      <img src={imagePreview} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                    ) : (
                      <div className="text-center opacity-30 group-hover:opacity-100 transition-opacity">
                        <ImageIcon className="w-12 h-12 mb-4 mx-auto" />
                        <p className="text-[10px] font-black uppercase tracking-[0.3em]">Upload Imagem</p>
                      </div>
                    )}
                    <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageChange} />
                  </div>
                </div>

                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">Nome do Produto</label>
                  <input name="nome" type="text" required defaultValue={editingProduct?.nome} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-lg font-bold italic" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">Categoria</label>
                  <select name="categoria" defaultValue={editingProduct?.categoria} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-sm font-bold uppercase tracking-widest text-white appearance-none">
                    {categories.map(cat => <option key={cat} value={cat} className="bg-zinc-900">{cat}</option>)}
                  </select>
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">SKU</label>
                  <input name="sku" type="text" required defaultValue={editingProduct?.sku} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white font-mono" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2">NCM</label>
                  <input name="ncm" type="text" required defaultValue={editingProduct?.ncm} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white font-mono" />
                </div>

                <div>
                  <label className="block text-[10px] font-black text-white/20 uppercase tracking-[0.4em] mb-3 ml-2 flex items-center gap-2">YouTube URL</label>
                  <input name="youtubeUrl" type="url" defaultValue={editingProduct?.youtubeUrl} className="w-full bg-white/5 border border-white/10 rounded-2xl p-5 outline-none focus:border-white text-sm" />
                </div>

