import { Product } from '../types';

// Substitua esta URL pela URL do seu serviço no Cloud Run ou Cloud Functions
const CLOUD_API_URL = 'https://seu-servico-google-cloud-run.a.run.app';

export const apiService = {
  /**
   * Busca todos os produtos do banco de dados no Google Cloud
   */
  async getProducts(): Promise<Product[]> {
    try {
      // Exemplo de chamada real:
      // const response = await fetch(`${CLOUD_API_URL}/produtos`);
      // return await response.json();

      // Simulação de latência de rede
      await new Promise(resolve => setTimeout(resolve, 1500));
      const saved = localStorage.getItem('5maxx_products');
      return saved ? JSON.parse(saved) : [];
    } catch (error) {
      console.error("Erro ao buscar produtos do Google Cloud:", error);
      throw error;
    }
  },

  /**
   * Salva ou atualiza um produto no banco de dados
   */
  async saveProduct(product: Product): Promise<Product> {
    try {
      // Exemplo de persistência real (POST/PUT):
      // const method = product.id.startsWith('temp_') ? 'POST' : 'PUT';
      // const response = await fetch(`${CLOUD_API_URL}/produtos`, {
      //   method,
      //   body: JSON.stringify(product),
      //   headers: { 'Content-Type': 'application/json' }
      // });
      // return await response.json();

      await new Promise(resolve => setTimeout(resolve, 2000));
      const products = await this.getProducts();
      const index = products.findIndex(p => p.id === product.id);

      let updatedProducts;
      if (index >= 0) {
        updatedProducts = [...products];
        updatedProducts[index] = product;
      } else {
        updatedProducts = [product, ...products];
      }

      localStorage.setItem('5maxx_products', JSON.stringify(updatedProducts));
      return product;
    } catch (error) {
      console.error("Erro ao salvar no Google Cloud:", error);
      throw error;
    }
  },

  /**
   * Remove um produto do banco de dados
   */
  async deleteProduct(id: string): Promise<void> {
    try {
      // await fetch(`${CLOUD_API_URL}/produtos/${id}`, { method: 'DELETE' });

      await new Promise(resolve => setTimeout(resolve, 1000));
      const products = await this.getProducts();
      const filtered = products.filter(p => p.id !== id);
      localStorage.setItem('5maxx_products', JSON.stringify(filtered));
    } catch (error) {
      console.error("Erro ao deletar no Google Cloud:", error);
      throw error;
    }
  }
};

