import { Product } from '../types';

/**
 * IMPORTANTE: 
 * Substitua esta URL pela URL da sua API implantada no Google Cloud Run.
 * Exemplo: 'https://api-5maxx-xpt0.a.run.app'
 */
const CLOUD_API_URL = 'SUA_URL_DO_CLOUD_RUN_AQUI';

export const apiService = {
  /**
   * Busca todos os produtos do MySQL via API
   */
  async getProducts(): Promise<Product[]> {
    try {
      const response = await fetch(`${CLOUD_API_URL}/produtos`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
      });

      if (!response.ok) {
        throw new Error(`Erro API: ${response.statusText}`);
      }

      return await response.json();
    } catch (error) {
      console.error("Erro ao buscar produtos do MySQL:", error);
      // Retornar array vazio ou lançar erro para o componente tratar
      throw error;
    }
  },

  /**
   * Salva ou atualiza um produto no MySQL via API
   */
  async saveProduct(product: Product): Promise<Product> {
    try {
      const isNew = product.id.startsWith('temp_');
      const url = isNew ? `${CLOUD_API_URL}/produtos` : `${CLOUD_API_URL}/produtos/${product.id}`;
      const method = isNew ? 'POST' : 'PUT';

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify(product),
      });

      if (!response.ok) {
        throw new Error(`Erro ao salvar: ${response.statusText}`);
      }

      return await response.json();
    } catch (error) {
      console.error("Erro ao salvar no MySQL:", error);
      throw error;
    }
  },

  /**
   * Remove um produto do MySQL via API
   */
  async deleteProduct(id: string): Promise<void> {
    try {
      const response = await fetch(`${CLOUD_API_URL}/produtos/${id}`, {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json'
        },
      });

      if (!response.ok) {
        throw new Error(`Erro ao deletar: ${response.statusText}`);
      }
    } catch (error) {
      console.error("Erro ao deletar no MySQL:", error);
      throw error;
    }
  }
};

