import { Product } from '../types';
import { MOCK_PRODUCTS } from '../constants';

const LOCAL_STORAGE_KEY = '5maxx_local_db';

/**
 * Serviço Mock para simulação de persistência local.
 * Permite que o Admin adicione, edite e exclua produtos sem necessidade de um servidor real.
 */
export const apiService = {
  /**
   * Busca todos os produtos do "banco de dados" local (localStorage)
   */
  async getProducts(): Promise<Product[]> {
    try {
      // Pequeno delay para simular carregamento real
      await new Promise(resolve => setTimeout(resolve, 800));

      const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (saved) {
        return JSON.parse(saved);
      }

      // Se estiver vazio, inicializa com os mocks padrão
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(MOCK_PRODUCTS));
      return MOCK_PRODUCTS;
    } catch (error) {
      console.error("Erro ao buscar produtos locais:", error);
      return MOCK_PRODUCTS;
    }
  },

  /**
   * Salva ou atualiza um produto no localStorage
   */
  async saveProduct(product: Product): Promise<Product> {
    try {
      await new Promise(resolve => setTimeout(resolve, 1000));
      const products = await this.getProducts();

      // Se for um ID temporário, remove o prefixo ou gera um novo ID final
      const cleanProduct = { ...product };
      if (cleanProduct.id.startsWith('temp_')) {
        cleanProduct.id = Math.random().toString(36).substr(2, 9).toUpperCase();
      }

      const index = products.findIndex(p => p.id === cleanProduct.id);

      let updatedProducts;
      if (index >= 0) {
        updatedProducts = [...products];
        updatedProducts[index] = cleanProduct;
      } else {
        updatedProducts = [cleanProduct, ...products];
      }

      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updatedProducts));
      return cleanProduct;
    } catch (error) {
      console.error("Erro ao salvar localmente:", error);
      throw error;
    }
  },

  /**
   * Remove um produto do localStorage
   */
  async deleteProduct(id: string): Promise<void> {
    try {
      await new Promise(resolve => setTimeout(resolve, 500));
      const products = await this.getProducts();
      const filtered = products.filter(p => p.id !== id);
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(filtered));
    } catch (error) {
      console.error("Erro ao deletar localmente:", error);
      throw error;
    }
  }
};

