import { Product, Resale, ResaleStock } from '../types';

/**
 * Serviço de API conectado ao backend PHP/MySQL
 * Importante: Substitua 'api.php' pelo caminho real no seu servidor
 */
const API_URL = 'api.php'; 

export const apiService = {
  async getProducts(): Promise<Product[]> {
    try {
      const response = await fetch(`${API_URL}?action=get_products`);
      const data = await response.json();
      // Mapear campos do banco (snake_case) para o frontend (camelCase)
      return data.map((p: any) => ({
        ...p,
        descricaoTecnica: p.descricao_tecnica,
        youtubeUrl: p.youtube_url,
        imageUrl: p.image_url
      }));
    } catch (error) {
      console.error("Erro ao buscar produtos:", error);
      return [];
    }
  },

  async saveProduct(product: Product): Promise<Product> {
    const clean = { ...product };
    if (clean.id.startsWith('temp_')) {
      clean.id = Math.random().toString(36).substr(2, 9).toUpperCase();
    }

    await fetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(clean)
    });

    return clean;
  },

  async deleteProduct(id: string): Promise<void> {
    await fetch(`${API_URL}?action=delete_product&id=${id}`, { method: 'DELETE' });
  },

  // --- Funções de Revenda ---

  async getResales(): Promise<Resale[]> {
    const response = await fetch(`${API_URL}?action=get_resales`);
    return await response.json();
  },

  async saveResale(resale: Resale): Promise<Resale> {
    const clean = { ...resale };
    if (clean.id.startsWith('temp_')) {
      clean.id = `RES_${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
    }

    await fetch(`${API_URL}?action=save_resale`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(clean)
    });

    return clean;
  },

  async deleteResale(id: string): Promise<void> {
    await fetch(`${API_URL}?action=delete_resale&id=${id}`, { method: 'DELETE' });
  },

  // --- Funções de Estoque de Revenda ---

  async getResaleStock(): Promise<ResaleStock[]> {
    const response = await fetch(`${API_URL}?action=get_stock`);
    return await response.json();
  },

  async updateResaleStock(resaleId: string, productId: string, quantidade: number): Promise<void> {
    await fetch(`${API_URL}?action=update_stock`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ resaleId, productId, quantidade })
    });
  }
};

import { Product, Resale, ResaleStock } from '../types';

/**
 * Serviço de API conectado ao backend PHP/MySQL
 */
const API_URL = 'api.php'; 

async function handleResponse(response: Response) {
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Erro na API (${response.status}): ${errorText}`);
  }
  const contentType = response.headers.get("content-type");
  if (contentType && contentType.indexOf("application/json") !== -1) {
    return await response.json();
  } else {
    const text = await response.text();
    throw new Error(`Resposta inesperada do servidor (não JSON): ${text.substring(0, 100)}`);
  }
}

export const apiService = {
  async getProducts(): Promise<Product[]> {
    try {
      const response = await fetch(`${API_URL}?action=get_products`);
      const data = await handleResponse(response);

      if (!Array.isArray(data)) return [];

      return data.map((p: any) => ({
        ...p,
        descricaoTecnica: p.descricao_tecnica || p.descricaoTecnica,
        youtubeUrl: p.youtube_url || p.youtubeUrl,
        imageUrl: p.image_url || p.imageUrl,
        preco: parseFloat(p.preco),
        estoque: parseInt(p.estoque)
      }));
    } catch (error) {
      console.error("Erro ao buscar produtos:", error);
      return [];
    }
  },

  async saveProduct(product: Product): Promise<Product> {
    const clean = { ...product };
    if (clean.id.startsWith('temp_')) {
      clean.id = Math.random().toString(36).substr(2, 9).toUpperCase();
    }

    try {
      const response = await fetch(`${API_URL}?action=save_product`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(clean)
      });
      await handleResponse(response);
      return clean;
    } catch (error) {
      console.error("Erro ao salvar produto:", error);
      throw error;
    }
  },

  async deleteProduct(id: string): Promise<void> {
    try {
      const response = await fetch(`${API_URL}?action=delete_product&id=${id}`, { method: 'DELETE' });
      await handleResponse(response);
    } catch (error) {
      console.error("Erro ao deletar produto:", error);
      throw error;
    }
  },

  // --- Funções de Revenda ---

  async getResales(): Promise<Resale[]> {
    try {
      const response = await fetch(`${API_URL}?action=get_resales`);
      const data = await handleResponse(response);
      return Array.isArray(data) ? data : [];
    } catch (error) {
      console.error("Erro ao buscar revendas:", error);
      return [];
    }
  },

  async saveResale(resale: Resale): Promise<Resale> {
    const clean = { ...resale };
    if (clean.id.startsWith('temp_')) {
      clean.id = `RES_${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
    }

    try {
      const response = await fetch(`${API_URL}?action=save_resale`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(clean)
      });
      await handleResponse(response);
      return clean;
    } catch (error) {
      console.error("Erro ao salvar revenda:", error);
      throw error;
    }
  },

  async deleteResale(id: string): Promise<void> {
    try {
      const response = await fetch(`${API_URL}?action=delete_resale&id=${id}`, { method: 'DELETE' });
      await handleResponse(response);
    } catch (error) {
      console.error("Erro ao deletar revenda:", error);
      throw error;
    }
  },

  // --- Funções de Estoque de Revenda ---

  async getResaleStock(): Promise<ResaleStock[]> {
    try {
      const response = await fetch(`${API_URL}?action=get_stock`);
      const data = await handleResponse(response);
      return Array.isArray(data) ? data.map((s: any) => ({
        ...s,
        quantidade: parseInt(s.quantidade)
      })) : [];
    } catch (error) {
      console.error("Erro ao buscar estoque das revendas:", error);
      return [];
    }
  },

  async updateResaleStock(resaleId: string, productId: string, quantidade: number): Promise<void> {
    try {
      const response = await fetch(`${API_URL}?action=update_stock`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ resaleId, productId, quantidade })
      });
      await handleResponse(response);
    } catch (error) {
      console.error("Erro ao atualizar estoque da revenda:", error);
      throw error;
    }
  }
};

import { Product, Resale, ResaleStock } from '../types';
import { MOCK_PRODUCTS, MOCK_RESALES, MOCK_RESALE_STOCK } from '../constants';

const DB_KEY = '5maxx_local_db';
const RESALE_KEY = '5maxx_resales';
const STOCK_KEY = '5maxx_resale_stock';

/**
 * Serviço de API simulado com localStorage para persistência offline.
 */
export const apiService = {
  async getProducts(): Promise<Product[]> {
    const saved = localStorage.getItem(DB_KEY);
    if (saved) return JSON.parse(saved);
    // Inicializa com dados fake se estiver vazio
    localStorage.setItem(DB_KEY, JSON.stringify(MOCK_PRODUCTS));
    return MOCK_PRODUCTS;
  },

  async saveProduct(product: Product): Promise<Product> {
    const products = await this.getProducts();
    const clean = { ...product };
    if (clean.id.startsWith('temp_')) {
      clean.id = Math.random().toString(36).substr(2, 9).toUpperCase();
    }
    const idx = products.findIndex(p => p.id === clean.id);
    const updated = idx >= 0 ? products.map(p => p.id === clean.id ? clean : p) : [clean, ...products];
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    return clean;
  },

  async deleteProduct(id: string): Promise<void> {
    const products = await this.getProducts();
    localStorage.setItem(DB_KEY, JSON.stringify(products.filter(p => p.id !== id)));
  },

  // --- Funções de Revenda (Persistência Local) ---

  async getResales(): Promise<Resale[]> {
    const saved = localStorage.getItem(RESALE_KEY);
    if (saved) return JSON.parse(saved);
    localStorage.setItem(RESALE_KEY, JSON.stringify(MOCK_RESALES));
    return MOCK_RESALES;
  },

  async saveResale(resale: Resale): Promise<Resale> {
    const resales = await this.getResales();
    const clean = { ...resale };
    if (clean.id.startsWith('temp_')) {
      clean.id = `RES_${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
    }
    const idx = resales.findIndex(r => r.id === clean.id);
    const updated = idx >= 0 ? resales.map(r => r.id === clean.id ? clean : r) : [clean, ...resales];
    localStorage.setItem(RESALE_KEY, JSON.stringify(updated));
    return clean;
  },

  async deleteResale(id: string): Promise<void> {
    const resales = await this.getResales();
    localStorage.setItem(RESALE_KEY, JSON.stringify(resales.filter(r => r.id !== id)));
  },

  // --- Funções de Estoque de Revenda (Persistência Local) ---

  async getResaleStock(): Promise<ResaleStock[]> {
    const saved = localStorage.getItem(STOCK_KEY);
    if (saved) return JSON.parse(saved);
    localStorage.setItem(STOCK_KEY, JSON.stringify(MOCK_RESALE_STOCK));
    return MOCK_RESALE_STOCK;
  },

  async updateResaleStock(resaleId: string, productId: string, quantidade: number): Promise<void> {
    const stocks = await this.getResaleStock();
    const idx = stocks.findIndex(s => s.resaleId === resaleId && s.productId === productId);
    let updated;
    if (idx >= 0) {
      updated = stocks.map((s, i) => i === idx ? { ...s, quantidade } : s);
    } else {
      updated = [...stocks, { resaleId, productId, quantidade }];
    }
    localStorage.setItem(STOCK_KEY, JSON.stringify(updated));
  }
};

